     6→/// A pattern recognizer for the smart input.
     7→///
     8→/// Each recognizer defines a [trigger] character, a [pattern] to match,
     9→/// and a [style] to apply to matched spans. When [showSuggestions] is `true`
    10→/// a suggestion popup is displayed after the user types the [trigger].
    11→///
    12→/// {@category Composites}
    13→class OiPatternRecognizer {
    14→  /// Creates an [OiPatternRecognizer].
    15→  const OiPatternRecognizer({
    16→    required this.trigger,
    17→    required this.pattern,
    18→    required this.style,
    19→    this.showSuggestions = false,
    20→  });
    21→
    22→  /// The trigger character (e.g., "@", "#", ":").
    23→  final String trigger;
    24→
    25→  /// The regex pattern to match.
    26→  final RegExp pattern;
    27→
    28→  /// The text style to apply to matched spans.
    29→  final TextStyle style;
    30→
    31→  /// Whether to show a suggestion popup when the trigger is typed.
    32→  final bool showSuggestions;
    33→}
