    35→/// A suggestion item for the smart input.
    36→///
    37→/// Used by [OiSmartInput.onSuggestionQuery] to provide completion candidates
    38→/// when a recognizer trigger is detected.
    39→///
    40→/// {@category Composites}
    41→class OiSuggestion {
    42→  /// Creates an [OiSuggestion].
    43→  const OiSuggestion({
    44→    required this.value,
    45→    required this.label,
    46→    this.leading,
    47→  });
    48→
    49→  /// The value to insert when this suggestion is selected.
    50→  final String value;
    51→
    52→  /// The display label shown in the suggestion list.
    53→  final String label;
    54→
    55→  /// An optional leading widget (e.g., avatar or icon).
    56→  final Widget? leading;
