    83→/// A text input that recognizes patterns and renders them inline.
    84→///
    85→/// Recognizes @mentions, #tags, :emoji:, dates, URLs, phone numbers,
    86→/// emails, etc. Each pattern gets distinct styling and can be tapped
    87→/// for actions.
    88→///
    89→/// Provide a list of [recognizers] to define the patterns to detect and
    90→/// their visual styling. Use [onSuggestionQuery] to supply suggestion
    91→/// candidates when a trigger character is typed. Use [onSpanTap] to
    92→/// respond when the user taps on a recognized span.
    93→///
    94→/// {@category Composites}
    95→class OiSmartInput extends StatefulWidget {
    96→  /// Creates an [OiSmartInput].
    97→  const OiSmartInput({
    98→    required this.label,
    99→    super.key,
   100→    this.value,
   101→    this.onChange,
   102→    this.recognizers = const [],
   103→    this.onSuggestionQuery,
   104→    this.onSpanTap,
   105→    this.placeholder,
   106→    this.maxLines = 1,
   107→    this.enabled = true,
   108→    this.hint,
   109→    this.error,
   110→    this.controller,
   111→    this.focusNode,
   112→  });
   113→
   114→  /// The label displayed above the input frame.
   115→  final String label;
   116→
   117→  /// The initial text value. Ignored when [controller] is provided.
   118→  final String? value;
   119→
   120→  /// Called when the text value changes.
   121→  final ValueChanged<String>? onChange;
   122→
   123→  /// The list of pattern recognizers to apply to the input text.
   124→  final List<OiPatternRecognizer> recognizers;
   125→
   126→  /// Called to fetch suggestions when a recognizer trigger is typed.
   127→  ///
   128→  /// Receives the trigger character and the current query text after the
   129→  /// trigger. Returns a future that resolves to a list of suggestions.
   130→  final Future<List<OiSuggestion>> Function(
   131→    String trigger,
   132→    String query,
   133→  )? onSuggestionQuery;
   134→
   135→  /// Called when the user taps on a recognized span.
   136→  final ValueChanged<OiRecognizedSpan>? onSpanTap;
   137→
   138→  /// Placeholder text shown inside the field when it is empty.
   139→  final String? placeholder;
   140→
   141→  /// Maximum number of lines for the input.
   142→  final int maxLines;
   143→
   144→  /// Whether the field accepts user input.
   145→  final bool enabled;
   146→
   147→  /// Optional hint text rendered below the input frame.
   148→  final String? hint;
   149→
   150→  /// Validation error message. When non-null the error border is shown.
   151→  final String? error;
   152→
   153→  /// An optional external controller. When null one is created internally.
   154→  final TextEditingController? controller;
   155→
   156→  /// An optional external focus node. When null one is created internally.
   157→  final FocusNode? focusNode;
   158→
   159→  @override
   160→  State<OiSmartInput> createState() => _OiSmartInputState();
   161→}
   162→
   163→class _OiSmartInputState extends State<OiSmartInput> {
   164→  late TextEditingController _controller;
   165→  late FocusNode _focusNode;
   166→  bool _ownsController = false;
   167→  bool _ownsFocusNode = false;
   168→  bool _focused = false;
   169→
   170→  @override
   171→  void initState() {
   172→    super.initState();
   173→    if (widget.controller == null) {
   174→      _controller = TextEditingController(text: widget.value);
   175→      _ownsController = true;
   176→    } else {
   177→      _controller = widget.controller!;
   178→    }
   179→    if (widget.focusNode == null) {
   180→      _focusNode = FocusNode();
   181→      _ownsFocusNode = true;
   182→    } else {
   183→      _focusNode = widget.focusNode!;
   184→    }
   185→    _focusNode.addListener(_handleFocusChange);
   186→    _controller.addListener(_handleTextChange);
   187→  }
   188→
   189→  @override
   190→  void didUpdateWidget(OiSmartInput oldWidget) {
   191→    super.didUpdateWidget(oldWidget);
   192→    if (oldWidget.controller != widget.controller) {
   193→      _controller.removeListener(_handleTextChange);
   194→      if (_ownsController) {
   195→        _controller.dispose();
   196→      }
   197→      if (widget.controller == null) {
   198→        _controller = TextEditingController(text: widget.value);
   199→        _ownsController = true;
   200→      } else {
   201→        _controller = widget.controller!;
   202→        _ownsController = false;
   203→      }
   204→      _controller.addListener(_handleTextChange);
   205→    }
   206→    if (oldWidget.focusNode != widget.focusNode) {
   207→      _focusNode.removeListener(_handleFocusChange);
   208→      if (_ownsFocusNode) {
   209→        _focusNode.dispose();
   210→      }
   211→      if (widget.focusNode == null) {
   212→        _focusNode = FocusNode();
   213→        _ownsFocusNode = true;
   214→      } else {
   215→        _focusNode = widget.focusNode!;
   216→        _ownsFocusNode = false;
   217→      }
   218→      _focusNode.addListener(_handleFocusChange);
   219→    }
   220→  }
   221→
   222→  @override
   223→  void dispose() {
   224→    _controller.removeListener(_handleTextChange);
   225→    _focusNode.removeListener(_handleFocusChange);
   226→    if (_ownsController) _controller.dispose();
   227→    if (_ownsFocusNode) _focusNode.dispose();
   228→    super.dispose();
   229→  }
   230→
   231→  void _handleFocusChange() {
   232→    final focused = _focusNode.hasFocus;
   233→    if (focused != _focused) {
   234→      setState(() => _focused = focused);
   235→    }
   236→  }
   237→
   238→  void _handleTextChange() {
   239→    setState(() {});
   240→    widget.onChange?.call(_controller.text);
   241→  }
   242→
   243→  // ── Pattern matching ───────────────────────────────────────────────────────
   244→
   245→  /// Builds a list of [TextSpan]s from the current text, applying recognizer
   246→  /// styles to matched portions.
   247→  List<InlineSpan> _buildTextSpans(String text, TextStyle baseStyle) {
   248→    if (widget.recognizers.isEmpty || text.isEmpty) {
   249→      return [TextSpan(text: text, style: baseStyle)];
   250→    }
   251→
   252→    // Collect all matches with their recognizer styles.
   253→    final matches = <_MatchEntry>[];
   254→    for (final recognizer in widget.recognizers) {
   255→      for (final match in recognizer.pattern.allMatches(text)) {
   256→        matches.add(
   257→          _MatchEntry(
   258→            start: match.start,
   259→            end: match.end,
   260→            style: recognizer.style,
   261→            trigger: recognizer.trigger,
   262→            value: match.group(0) ?? '',
   263→          ),
   264→        );
   265→      }
   266→    }
   267→
   268→    if (matches.isEmpty) {
   269→      return [TextSpan(text: text, style: baseStyle)];
   270→    }
   271→
   272→    // Sort by start position; on tie, longer match first.
   273→    matches.sort((a, b) {
   274→      final cmp = a.start.compareTo(b.start);
   275→      if (cmp != 0) return cmp;
   276→      return b.end.compareTo(a.end);
   277→    });
   278→
   279→    // Remove overlapping matches (keep the earliest / longest).
   280→    final filtered = <_MatchEntry>[];
   281→    var lastEnd = 0;
   282→    for (final m in matches) {
   283→      if (m.start >= lastEnd) {
   284→        filtered.add(m);
   285→        lastEnd = m.end;
   286→      }
   287→    }
   288→
   289→    // Build spans.
   290→    final spans = <InlineSpan>[];
   291→    var cursor = 0;
   292→    for (final m in filtered) {
   293→      if (m.start > cursor) {
   294→        spans.add(TextSpan(text: text.substring(cursor, m.start), style: baseStyle));
   295→      }
   296→
   297→      final span = OiRecognizedSpan(
   298→        trigger: m.trigger,
   299→        value: m.value,
   300→        range: TextRange(start: m.start, end: m.end),
   301→      );
   302→
   303→      spans.add(
   304→        WidgetSpan(
   305→          alignment: PlaceholderAlignment.baseline,
   306→          baseline: TextBaseline.alphabetic,
   307→          child: GestureDetector(
   308→            onTap: widget.onSpanTap != null ? () => widget.onSpanTap!(span) : null,
   309→            child: Text(
   310→              m.value,
   311→              style: baseStyle.merge(m.style),
   312→            ),
   313→          ),
   314→        ),
   315→      );
   316→      cursor = m.end;
   317→    }
   318→    if (cursor < text.length) {
   319→      spans.add(TextSpan(text: text.substring(cursor), style: baseStyle));
   320→    }
   321→    return spans;
   322→  }
   323→
   324→  // ── Build ──────────────────────────────────────────────────────────────────
   325→
   326→  @override
   327→  Widget build(BuildContext context) {
   328→    final themeData = OiTheme.maybeOf(context);
   329→    final baseStyle = themeData?.textTheme.styleFor(OiLabelVariant.body) ??
   330→        const TextStyle(fontSize: 16, fontWeight: FontWeight.w400);
   331→    final cursorColor = themeData?.colors.primary.base ?? const Color(0xFF000000);
   332→
   333→    final text = _controller.text;
   334→    final showPlaceholder = text.isEmpty && widget.placeholder != null;
   335→
   336→    // The rich-text display overlay showing pattern-styled spans.
   337→    Widget richOverlay;
   338→    if (text.isNotEmpty && widget.recognizers.isNotEmpty) {
   339→      final spans = _buildTextSpans(text, baseStyle);
   340→      richOverlay = IgnorePointer(
   341→        child: Text.rich(
   342→          TextSpan(children: spans),
   343→          maxLines: widget.maxLines == 1 ? 1 : null,
   344→        ),
   345→      );
   346→    } else {
   347→      richOverlay = const SizedBox.shrink();
   348→    }
   349→
   350→    // The underlying editable text.
   351→    final editableText = EditableText(
   352→      controller: _controller,
   353→      focusNode: _focusNode,
   354→      style: widget.recognizers.isNotEmpty
   355→          ? baseStyle.copyWith(color: const Color(0x00000000))
   356→          : baseStyle,
   357→      cursorColor: cursorColor,
   358→      backgroundCursorColor: const Color(0xFF000000),
   359→      maxLines: widget.maxLines,
   360→      readOnly: !widget.enabled,
   361→      onChanged: (_) {},
   362→      selectionColor: cursorColor.withValues(alpha: 0.3),
   363→    );
   364→
   365→    // Stack the rich overlay on top of the invisible editable text so the
   366→    // user sees styled text while typing into the actual field.
   367→    Widget field;
   368→    if (widget.recognizers.isNotEmpty) {
   369→      field = Stack(
   370→        children: [
   371→          // Placeholder
   372→          if (showPlaceholder)
   373→            Positioned.fill(
   374→              child: IgnorePointer(
   375→                child: Align(
   376→                  alignment: Alignment.centerLeft,
   377→                  child: Text(
   378→                    widget.placeholder!,
   379→                    style: baseStyle.copyWith(
   380→                      color: (baseStyle.color ?? const Color(0xFF000000))
   381→                          .withValues(alpha: 0.45),
   382→                    ),
   383→                    maxLines: 1,
   384→                    overflow: TextOverflow.ellipsis,
   385→                  ),
   386→                ),
   387→              ),
   388→            ),
   389→          editableText,
   390→          Positioned.fill(child: richOverlay),
   391→        ],
   392→      );
   393→    } else {
   394→      // No recognizers — render as plain input with visible text.
   395→      field = Stack(
   396→        children: [
   397→          if (showPlaceholder)
   398→            Positioned.fill(
   399→              child: IgnorePointer(
   400→                child: Align(
   401→                  alignment: Alignment.centerLeft,
   402→                  child: Text(
   403→                    widget.placeholder!,
   404→                    style: baseStyle.copyWith(
   405→                      color: (baseStyle.color ?? const Color(0xFF000000))
   406→                          .withValues(alpha: 0.45),
   407→                    ),
   408→                    maxLines: 1,
   409→                    overflow: TextOverflow.ellipsis,
   410→                  ),
   411→                ),
   412→              ),
   413→            ),
   414→          EditableText(
   415→            controller: _controller,
   416→            focusNode: _focusNode,
   417→            style: baseStyle,
   418→            cursorColor: cursorColor,
   419→            backgroundCursorColor: const Color(0xFF000000),
   420→            maxLines: widget.maxLines,
   421→            readOnly: !widget.enabled,
   422→            onChanged: (_) {},
   423→            selectionColor: cursorColor.withValues(alpha: 0.3),
   424→          ),
   425→        ],
   426→      );
   427→    }
   428→
   429→    return Semantics(
   430→      label: widget.label,
   431→      textField: true,
   432→      enabled: widget.enabled,
   433→      child: OiInputFrame(
   434→        label: widget.label,
   435→        hint: widget.hint,
   436→        error: widget.error,
   437→        focused: _focused,
   438→        enabled: widget.enabled,
   439→        child: field,
   440→      ),
   441→    );
   442→  }
   443→}
   444→
   445→/// Internal helper to track a regex match with its recognizer style.
   446→class _MatchEntry {
   447→  const _MatchEntry({
   448→    required this.start,
   449→    required this.end,
   450→    required this.style,
   451→    required this.trigger,
   452→    required this.value,
   453→  });
   454→
   455→  final int start;
   456→  final int end;
   457→  final TextStyle style;
   458→  final String trigger;
   459→  final String value;
   460→}
