    70→// ── OiFormField ─────────────────────────────────────────────────────────────
    71→
    72→/// A declarative description of a single field within an [OiForm].
    73→///
    74→/// Each field has a unique [key], a display [label], and a [type] that
    75→/// determines which widget is rendered. Optional [validate] and [required]
    76→/// properties control validation.
    77→///
    78→/// {@category Composites}
    79→@immutable
    80→class OiFormField {
    81→  /// Creates an [OiFormField].
    82→  const OiFormField({
    83→    required this.key,
    84→    required this.label,
    85→    required this.type,
    86→    this.defaultValue,
    87→    this.required = false,
    88→    this.validate,
    89→    this.config,
    90→    this.customBuilder,
    91→  });
    92→
    93→  /// A unique identifier for this field, used as the key in form values.
    94→  final String key;
    95→
    96→  /// The human-readable label rendered above or beside the input.
    97→  final String label;
    98→
    99→  /// The type of input widget to render.
   100→  final OiFieldType type;
   101→
   102→  /// The default value for this field when the form is first created.
   103→  final dynamic defaultValue;
   104→
   105→  /// Whether this field must have a non-null, non-empty value to pass
   106→  /// validation.
   107→  final bool required;
   108→
   109→  /// An optional validation function. Returns an error message string when
   110→  /// the value is invalid, or `null` when valid.
   111→  final String? Function(dynamic)? validate;
   112→
   113→  /// Extra configuration passed to the rendered widget (e.g. options for
   114→  /// a select field, min/max for a number field).
   115→  final Map<String, dynamic>? config;
   116→
   117→  /// A builder for [OiFieldType.custom] fields. Receives the current value
   118→  /// and a callback to update it.
   119→  final Widget Function(dynamic value, ValueChanged<dynamic>)? customBuilder;
   120→}
