   145→// ── OiFormController ────────────────────────────────────────────────────────
   146→
   147→/// Controller managing form state: values, validation errors, dirty flags.
   148→///
   149→/// Extend or compose with this controller to drive an [OiForm] widget.
   150→/// Notifies listeners on every value or error change.
   151→///
   152→/// {@category Composites}
   153→class OiFormController extends ChangeNotifier {
   154→  /// Creates an [OiFormController] with optional [initialValues].
   155→  OiFormController({Map<String, dynamic>? initialValues})
   156→      : _values = Map<String, dynamic>.from(initialValues ?? {}),
   157→        _initialValues = Map<String, dynamic>.from(initialValues ?? {});
   158→
   159→  final Map<String, dynamic> _values;
   160→  final Map<String, dynamic> _initialValues;
   161→  final Map<String, String?> _errors = {};
   162→
   163→  /// Gets all current form values as an unmodifiable map.
   164→  Map<String, dynamic> get values => Map<String, dynamic>.unmodifiable(_values);
   165→
   166→  /// Gets a specific field value by [key], cast to [T].
   167→  T? getValue<T>(String key) => _values[key] as T?;
   168→
   169→  /// Sets a field value and notifies listeners.
   170→  void setValue(String key, dynamic value) {
   171→    _values[key] = value;
   172→    notifyListeners();
   173→  }
   174→
   175→  /// Gets the validation error for a specific field.
   176→  String? getError(String key) => _errors[key];
   177→
   178→  /// Sets an error for a specific field and notifies listeners.
   179→  ///
   180→  /// Pass `null` to clear the error.
   181→  void setError(String key, String? error) {
   182→    _errors[key] = error;
   183→    notifyListeners();
   184→  }
   185→
   186→  /// Whether the form has no validation errors.
   187→  bool get isValid => _errors.values.every((e) => e == null);
   188→
   189→  /// Whether any field has been modified from its initial value.
   190→  bool get isDirty {
   191→    for (final entry in _values.entries) {
   192→      if (_initialValues[entry.key] != entry.value) return true;
   193→    }
   194→    return false;
   195→  }
   196→
   197→  /// Resets all fields to their initial values and clears errors.
   198→  void reset() {
   199→    _values
   200→      ..clear()
   201→      ..addAll(Map<String, dynamic>.from(_initialValues));
   202→    _errors.clear();
   203→    notifyListeners();
   204→  }
   205→
   206→  /// Validates all fields using the provided [validators] map.
   207→  ///
   208→  /// Each validator receives the current field value and returns an error
   209→  /// string or `null`. Returns `true` when all fields pass validation.
   210→  bool validate(Map<String, String? Function(dynamic)> validators) {
   211→    for (final entry in validators.entries) {
   212→      final error = entry.value(_values[entry.key]);
   213→      _errors[entry.key] = error;
   214→    }
   215→    notifyListeners();
   216→    return isValid;
   217→  }
   218→}
