   220→// ── OiForm ──────────────────────────────────────────────────────────────────
   221→
   222→/// A form system that renders sections of fields with validation.
   223→///
   224→/// Renders form fields from [OiFormField] configurations, handling
   225→/// validation, conditional visibility, dirty detection, and submission.
   226→/// Field values are stored in the provided [controller].
   227→///
   228→/// {@category Composites}
   229→class OiForm extends StatefulWidget {
   230→  /// Creates an [OiForm].
   231→  const OiForm({
   232→    super.key,
   233→    required this.sections,
   234→    required this.controller,
   235→    this.onSubmit,
   236→    this.onCancel,
   237→    this.autoValidate = false,
   238→    this.conditions,
   239→    this.dependencies,
   240→    this.autosave,
   241→    this.dirtyDetection = true,
   242→    this.undoRedo = false,
   243→    this.layout = OiFormLayout.vertical,
   244→  });
   245→
   246→  /// The sections of fields to render.
   247→  final List<OiFormSection> sections;
   248→
   249→  /// The controller that manages field values, errors, and dirty state.
   250→  final OiFormController controller;
   251→
   252→  /// Called when the form is submitted with the current values.
   253→  final ValueChanged<Map<String, dynamic>>? onSubmit;
   254→
   255→  /// Called when the user cancels the form.
   256→  final VoidCallback? onCancel;
   257→
   258→  /// When `true`, fields are validated on every change.
   259→  final bool autoValidate;
   260→
   261→  /// Conditional visibility rules. Each key is a field key, and the function
   262→  /// returns `true` when the field should be visible, based on all values.
   263→  final Map<String, bool Function(Map<String, dynamic>)>? conditions;
   264→
   265→  /// Dependency callbacks. When any value changes, each dependency function
   266→  /// is called with the full value map, allowing fields to react to
   267→  /// sibling changes.
   268→  final Map<String, void Function(Map<String, dynamic>)>? dependencies;
   269→
   270→  /// When non-null the form auto-saves at this interval.
   271→  final Duration? autosave;
   272→
   273→  /// Whether to enable dirty detection (submit disabled when not dirty).
   274→  final bool dirtyDetection;
   275→
   276→  /// Whether to enable undo/redo support.
   277→  final bool undoRedo;
   278→
   279→  /// The layout direction for form fields.
   280→  final OiFormLayout layout;
   281→
   282→  @override
   283→  State<OiForm> createState() => _OiFormState();
   284→}
   285→
   286→class _OiFormState extends State<OiForm> {
   287→  Timer? _autosaveTimer;
   288→  bool _validating = false;
   289→
   290→  @override
   291→  void initState() {
   292→    super.initState();
   293→    _initDefaults();
   294→    widget.controller.addListener(_onControllerChange);
   295→    _startAutosave();
   296→  }
   297→
   298→  @override
   299→  void didUpdateWidget(OiForm oldWidget) {
   300→    super.didUpdateWidget(oldWidget);
   301→    if (oldWidget.controller != widget.controller) {
   302→      oldWidget.controller.removeListener(_onControllerChange);
   303→      widget.controller.addListener(_onControllerChange);
   304→    }
   305→    if (oldWidget.autosave != widget.autosave) {
   306→      _autosaveTimer?.cancel();
   307→      _startAutosave();
   308→    }
   309→  }
   310→
   311→  @override
   312→  void dispose() {
   313→    widget.controller.removeListener(_onControllerChange);
   314→    _autosaveTimer?.cancel();
   315→    super.dispose();
   316→  }
   317→
   318→  void _initDefaults() {
   319→    for (final section in widget.sections) {
   320→      for (final field in section.fields) {
   321→        if (field.defaultValue != null &&
   322→            widget.controller.getValue<dynamic>(field.key) == null) {
   323→          widget.controller.setValue(field.key, field.defaultValue);
   324→        }
   325→      }
   326→    }
   327→  }
   328→
   329→  void _startAutosave() {
   330→    if (widget.autosave != null) {
   331→      _autosaveTimer = Timer.periodic(widget.autosave!, (_) {
   332→        widget.onSubmit?.call(widget.controller.values);
   333→      });
   334→    }
   335→  }
   336→
   337→  void _onControllerChange() {
   338→    // Guard against re-entrant calls from setError -> notifyListeners.
   339→    if (_validating) return;
   340→
   341→    // Run dependencies.
   342→    if (widget.dependencies != null) {
   343→      for (final dep in widget.dependencies!.values) {
   344→        dep(widget.controller.values);
   345→      }
   346→    }
   347→
   348→    // Auto-validate.
   349→    if (widget.autoValidate) {
   350→      _validateAll();
   351→    }
   352→
   353→    setState(() {});
   354→  }
   355→
   356→  void _validateAll() {
   357→    _validating = true;
   358→    try {
   359→      for (final section in widget.sections) {
   360→        for (final field in section.fields) {
   361→          _validateField(field);
   362→        }
   363→      }
   364→    } finally {
   365→      _validating = false;
   366→    }
   367→  }
   368→
   369→  void _validateField(OiFormField field) {
   370→    final value = widget.controller.getValue<dynamic>(field.key);
   371→
   372→    // Required check.
   373→    if (field.required) {
   374→      if (value == null || (value is String && value.isEmpty)) {
   375→        widget.controller.setError(field.key, '${field.label} is required');
   376→        return;
   377→      }
   378→    }
   379→
   380→    // Custom validator.
   381→    if (field.validate != null) {
   382→      final error = field.validate!(value);
   383→      widget.controller.setError(field.key, error);
   384→      return;
   385→    }
   386→
   387→    widget.controller.setError(field.key, null);
   388→  }
   389→
   390→  void _handleSubmit() {
   391→    _validateAll();
   392→    if (widget.controller.isValid) {
   393→      widget.onSubmit?.call(widget.controller.values);
   394→    }
   395→  }
   396→
   397→  void _handleCancel() {
   398→    widget.controller.reset();
   399→    widget.onCancel?.call();
   400→  }
   401→
   402→  bool _isFieldVisible(OiFormField field) {
   403→    if (widget.conditions == null) return true;
   404→    final condition = widget.conditions![field.key];
   405→    if (condition == null) return true;
   406→    return condition(widget.controller.values);
   407→  }
   408→
   409→  // ---------------------------------------------------------------------------
   410→  // Field builders
   411→  // ---------------------------------------------------------------------------
   412→
   413→  Widget _buildField(BuildContext context, OiFormField field) {
   414→    final value = widget.controller.getValue<dynamic>(field.key);
   415→    final error = widget.controller.getError(field.key);
   416→
   417→    switch (field.type) {
   418→      case OiFieldType.text:
   419→        return OiTextInput(
   420→          key: ValueKey('oi_form_field_${field.key}'),
   421→          label: field.label,
   422→          error: error,
   423→          onChanged: (v) => widget.controller.setValue(field.key, v),
   424→          controller: TextEditingController(text: value as String? ?? ''),
   425→        );
   426→
   427→      case OiFieldType.number:
   428→        return OiNumberInput(
   429→          key: ValueKey('oi_form_field_${field.key}'),
   430→          label: field.label,
   431→          error: error,
   432→          value: value as double?,
   433→          onChanged: (v) => widget.controller.setValue(field.key, v),
   434→          min: field.config?['min'] as double?,
   435→          max: field.config?['max'] as double?,
   436→          step: (field.config?['step'] as double?) ?? 1,
   437→        );
   438→
   439→      case OiFieldType.checkbox:
   440→        final boolValue = value as bool? ?? false;
   441→        return OiCheckbox(
   442→          key: ValueKey('oi_form_field_${field.key}'),
   443→          value:
   444→              boolValue ? OiCheckboxState.checked : OiCheckboxState.unchecked,
   445→          label: field.label,
   446→          onChanged: (v) => widget.controller.setValue(field.key, v),
   447→        );
   448→
   449→      case OiFieldType.switchField:
   450→        return OiSwitch(
   451→          key: ValueKey('oi_form_field_${field.key}'),
   452→          value: value as bool? ?? false,
   453→          label: field.label,
   454→          onChanged: (v) => widget.controller.setValue(field.key, v),
   455→        );
   456→
   457→      case OiFieldType.select:
   458→        final options =
   459→            (field.config?['options'] as List<OiSelectOption<dynamic>>?) ?? [];
   460→        return OiSelect<dynamic>(
   461→          key: ValueKey('oi_form_field_${field.key}'),
   462→          label: field.label,
   463→          error: error,
   464→          value: value,
   465→          options: options,
   466→          onChanged: (v) => widget.controller.setValue(field.key, v),
   467→        );
   468→
   469→      case OiFieldType.custom:
   470→        if (field.customBuilder != null) {
   471→          return field.customBuilder!(
   472→            value,
   473→            (v) => widget.controller.setValue(field.key, v),
   474→          );
   475→        }
   476→        return const SizedBox.shrink();
   477→
   478→      case OiFieldType.date:
   479→      case OiFieldType.time:
   480→      case OiFieldType.radio:
   481→      case OiFieldType.slider:
   482→      case OiFieldType.color:
   483→      case OiFieldType.file:
   484→        // Fallback for field types that are not yet implemented with
   485→        // dedicated widgets. Render a text input with the field label.
   486→        return OiTextInput(
   487→          key: ValueKey('oi_form_field_${field.key}'),
   488→          label: field.label,
   489→          error: error,
   490→          onChanged: (v) => widget.controller.setValue(field.key, v),
   491→        );
   492→    }
   493→  }
   494→
   495→  // ---------------------------------------------------------------------------
   496→  // Section builder
   497→  // ---------------------------------------------------------------------------
   498→
   499→  Widget _buildSection(BuildContext context, OiFormSection section) {
   500→    final colors = context.colors;
   501→    final visibleFields =
   502→        section.fields.where(_isFieldVisible).toList();
   503→
   504→    if (visibleFields.isEmpty) return const SizedBox.shrink();
   505→
   506→    return Column(
   507→      crossAxisAlignment: CrossAxisAlignment.start,
   508→      mainAxisSize: MainAxisSize.min,
   509→      children: [
   510→        if (section.title != null)
   511→          Padding(
   512→            padding: const EdgeInsets.only(bottom: 4),
   513→            child: Text(
   514→              section.title!,
   515→              style: TextStyle(
   516→                fontSize: 16,
   517→                fontWeight: FontWeight.w600,
   518→                color: colors.text,
   519→              ),
   520→            ),
   521→          ),
   522→        if (section.description != null)
   523→          Padding(
   524→            padding: const EdgeInsets.only(bottom: 8),
   525→            child: Text(
   526→              section.description!,
   527→              style: TextStyle(
   528→                fontSize: 13,
   529→                color: colors.textMuted,
   530→              ),
   531→            ),
   532→          ),
   533→        ..._layoutFields(context, visibleFields),
   534→      ],
   535→    );
   536→  }
   537→
   538→  List<Widget> _layoutFields(
   539→      BuildContext context, List<OiFormField> fields) {
   540→    switch (widget.layout) {
   541→      case OiFormLayout.vertical:
   542→        return fields
   543→            .map((f) => Padding(
   544→                  padding: const EdgeInsets.only(bottom: 12),
   545→                  child: _buildField(context, f),
   546→                ))
   547→            .toList();
   548→
   549→      case OiFormLayout.horizontal:
   550→        return [
   551→          Row(
   552→            crossAxisAlignment: CrossAxisAlignment.start,
   553→            children: fields
   554→                .map((f) => Expanded(
   555→                      child: Padding(
   556→                        padding: const EdgeInsets.only(right: 12),
   557→                        child: _buildField(context, f),
   558→                      ),
   559→                    ))
   560→                .toList(),
   561→          ),
   562→        ];
   563→
   564→      case OiFormLayout.inline:
   565→        return [
   566→          Wrap(
   567→            spacing: 12,
   568→            runSpacing: 12,
   569→            children: fields
   570→                .map((f) => _buildField(context, f))
   571→                .toList(),
   572→          ),
   573→        ];
   574→    }
   575→  }
   576→
   577→  // ---------------------------------------------------------------------------
   578→  // Build
   579→  // ---------------------------------------------------------------------------
   580→
   581→  @override
   582→  Widget build(BuildContext context) {
   583→    final colors = context.colors;
   584→    final canSubmit = !widget.dirtyDetection || widget.controller.isDirty;
   585→
   586→    return Column(
   587→      crossAxisAlignment: CrossAxisAlignment.start,
   588→      mainAxisSize: MainAxisSize.min,
   589→      children: [
   590→        for (final section in widget.sections)
   591→          Padding(
   592→            padding: const EdgeInsets.only(bottom: 16),
   593→            child: _buildSection(context, section),
   594→          ),
   595→        Row(
   596→          mainAxisAlignment: MainAxisAlignment.end,
   597→          children: [
   598→            if (widget.onCancel != null)
   599→              GestureDetector(
   600→                onTap: _handleCancel,
   601→                child: Padding(
   602→                  padding: const EdgeInsets.symmetric(
   603→                      horizontal: 16, vertical: 8),
   604→                  child: Text(
   605→                    'Cancel',
   606→                    style: TextStyle(
   607→                      fontSize: 14,
   608→                      color: colors.textMuted,
   609→                    ),
   610→                  ),
   611→                ),
   612→              ),
   613→            if (widget.onSubmit != null)
   614→              GestureDetector(
   615→                onTap: canSubmit ? _handleSubmit : null,
   616→                child: Container(
   617→                  padding: const EdgeInsets.symmetric(
   618→                      horizontal: 16, vertical: 8),
   619→                  decoration: BoxDecoration(
   620→                    color: canSubmit
   621→                        ? colors.primary.base
   622→                        : colors.borderSubtle,
   623→                    borderRadius: BorderRadius.circular(6),
   624→                  ),
   625→                  child: Text(
   626→                    'Submit',
   627→                    style: TextStyle(
   628→                      fontSize: 14,
   629→                      color: canSubmit
   630→                          ? colors.textOnPrimary
   631→                          : colors.textMuted,
   632→                    ),
   633→                  ),
   634→                ),
   635→              ),
   636→          ],
   637→        ),
   638→      ],
   639→    );
   640→  }
   641→}
