     4→/// The style of the stepper.
     5→///
     6→/// Determines the layout direction and visual density of the step indicators.
     7→///
     8→/// {@category Composites}
     9→enum OiStepperStyle {
    10→  /// Steps are laid out in a horizontal row with connecting lines.
    11→  horizontal,
    12→
    13→  /// Steps are laid out in a vertical column with connecting lines.
    14→  vertical,
    15→
    16→  /// A compact text-only mode showing "Step N of M".
    17→  compact,
    18→}
    19→
    20→/// A visual step indicator showing progress through a multi-step process.
    21→///
    22→/// Used by [OiWizard] but also available standalone. Shows steps as
    23→/// connected dots/circles with labels, highlighting the current step
    24→/// and marking completed/error steps.
    25→///
    26→/// {@category Composites}
    27→class OiStepper extends StatelessWidget {
    28→  /// Creates an [OiStepper].
    29→  const OiStepper({
    30→    super.key,
    31→    required this.totalSteps,
    32→    required this.currentStep,
    33→    this.stepLabels,
    34→    this.stepIcons,
    35→    this.style = OiStepperStyle.horizontal,
    36→    this.onStepTap,
    37→    this.completedSteps = const {},
    38→    this.errorSteps = const {},
    39→  });
    40→
    41→  /// The total number of steps in the process.
    42→  final int totalSteps;
    43→
    44→  /// The zero-based index of the currently active step.
    45→  final int currentStep;
    46→
    47→  /// Optional labels displayed below (horizontal) or beside (vertical)
    48→  /// each step indicator. Must have [totalSteps] entries when provided.
    49→  final List<String>? stepLabels;
    50→
    51→  /// Optional icons displayed inside each step circle.
    52→  /// Must have [totalSteps] entries when provided.
    53→  final List<IconData>? stepIcons;
    54→
    55→  /// The visual layout style of the stepper.
    56→  final OiStepperStyle style;
    57→
    58→  /// Called when the user taps a step circle, with the step index.
    59→  final ValueChanged<int>? onStepTap;
    60→
    61→  /// Set of step indices that are completed. Completed steps show a
    62→  /// checkmark icon.
    63→  final Set<int> completedSteps;
    64→
    65→  /// Set of step indices that have errors. Error steps show an error icon
    66→  /// and use the error color.
    67→  final Set<int> errorSteps;
    68→
    69→  // ---------------------------------------------------------------------------
    70→  // Icon constants
    71→  // ---------------------------------------------------------------------------
    72→
    73→  /// Material Icons check mark.
    74→  static const IconData _checkIcon =
    75→      IconData(0xe5ca, fontFamily: 'MaterialIcons');
    76→
    77→  /// Material Icons error (exclamation circle).
    78→  static const IconData _errorIcon =
    79→      IconData(0xe000, fontFamily: 'MaterialIcons');
    80→
    81→  // ---------------------------------------------------------------------------
    82→  // Build helpers
    83→  // ---------------------------------------------------------------------------
    84→
    85→  /// Returns the color for a step at [index].
    86→  Color _stepColor(BuildContext context, int index) {
    87→    final colors = context.colors;
    88→    if (errorSteps.contains(index)) return colors.error.base;
    89→    if (completedSteps.contains(index)) return colors.success.base;
    90→    if (index == currentStep) return colors.primary.base;
    91→    return colors.borderSubtle;
    92→  }
    93→
    94→  /// Builds the icon inside a step circle at [index].
    95→  Widget? _stepIcon(BuildContext context, int index) {
    96→    final colors = context.colors;
    97→    if (errorSteps.contains(index)) {
    98→      return Icon(
    99→        _errorIcon,
   100→        size: 14,
   101→        color: colors.textOnPrimary,
   102→      );
   103→    }
   104→    if (completedSteps.contains(index)) {
   105→      return Icon(
   106→        _checkIcon,
   107→        size: 14,
   108→        color: colors.textOnPrimary,
   109→      );
   110→    }
   111→    if (stepIcons != null && index < stepIcons!.length) {
   112→      return Icon(
   113→        stepIcons![index],
   114→        size: 14,
   115→        color: index == currentStep
   116→            ? colors.textOnPrimary
   117→            : colors.textMuted,
   118→      );
   119→    }
   120→    return null;
   121→  }
   122→
   123→  /// Builds a single step circle at [index].
   124→  Widget _buildStep(BuildContext context, int index) {
   125→    final colors = context.colors;
   126→    final color = _stepColor(context, index);
   127→    final isCurrent = index == currentStep;
   128→    const circleSize = 28.0;
   129→
   130→    final icon = _stepIcon(context, index);
   131→
   132→    Widget circle = Container(
   133→      width: circleSize,
   134→      height: circleSize,
   135→      decoration: BoxDecoration(
   136→        color: (completedSteps.contains(index) ||
   137→                errorSteps.contains(index) ||
   138→                isCurrent)
   139→            ? color
   140→            : colors.surface,
   141→        shape: BoxShape.circle,
   142→        border: Border.all(color: color, width: 2),
   143→      ),
   144→      child: Center(
   145→        child: icon ??
   146→            Text(
   147→              '${index + 1}',
   148→              style: TextStyle(
   149→                fontSize: 12,
   150→                fontWeight: FontWeight.w600,
   151→                color: isCurrent ? colors.textOnPrimary : colors.textMuted,
   152→              ),
   153→            ),
   154→      ),
   155→    );
   156→
   157→    if (onStepTap != null) {
   158→      circle = GestureDetector(
   159→        onTap: () => onStepTap!(index),
   160→        behavior: HitTestBehavior.opaque,
   161→        child: circle,
   162→      );
   163→    }
   164→
   165→    return circle;
   166→  }
   167→
   168→  /// Builds a connector line between steps.
   169→  Widget _buildConnector(BuildContext context, int beforeIndex) {
   170→    final colors = context.colors;
   171→    final isCompleted = completedSteps.contains(beforeIndex);
   172→    final lineColor =
   173→        isCompleted ? colors.success.base : colors.borderSubtle;
   174→
   175→    if (style == OiStepperStyle.horizontal) {
   176→      return Expanded(
   177→        child: Container(
   178→          height: 2,
   179→          color: lineColor,
   180→        ),
   181→      );
   182→    }
   183→
   184→    return Container(
   185→      width: 2,
   186→      height: 24,
   187→      color: lineColor,
   188→    );
   189→  }
   190→
   191→  /// Builds the compact representation: "Step N of M".
   192→  Widget _buildCompact(BuildContext context) {
   193→    final colors = context.colors;
   194→    return Semantics(
   195→      label: 'Step ${currentStep + 1} of $totalSteps',
   196→      child: Text(
   197→        'Step ${currentStep + 1} of $totalSteps',
   198→        style: TextStyle(
   199→          fontSize: 14,
   200→          fontWeight: FontWeight.w500,
   201→          color: colors.text,
   202→        ),
   203→      ),
   204→    );
   205→  }
   206→
   207→  /// Builds the horizontal layout.
   208→  Widget _buildHorizontal(BuildContext context) {
   209→    final children = <Widget>[];
   210→
   211→    for (var i = 0; i < totalSteps; i++) {
   212→      if (i > 0) {
   213→        children.add(_buildConnector(context, i - 1));
   214→      }
   215→
   216→      final step = _buildStep(context, i);
   217→
   218→      if (stepLabels != null && i < stepLabels!.length) {
   219→        children.add(
   220→          Column(
   221→            mainAxisSize: MainAxisSize.min,
   222→            children: [
   223→              step,
   224→              const SizedBox(height: 4),
   225→              Text(
   226→                stepLabels![i],
   227→                style: TextStyle(
   228→                  fontSize: 11,
   229→                  color: i == currentStep
   230→                      ? context.colors.text
   231→                      : context.colors.textMuted,
   232→                ),
   233→              ),
   234→            ],
   235→          ),
   236→        );
   237→      } else {
   238→        children.add(step);
   239→      }
   240→    }
   241→
   242→    return Row(
   243→      mainAxisSize: MainAxisSize.min,
   244→      crossAxisAlignment: CrossAxisAlignment.center,
   245→      children: children,
   246→    );
   247→  }
