   256→          Padding(
   257→            padding: const EdgeInsets.only(left: 13),
   258→            child: _buildConnector(context, i - 1),
   259→          ),
   260→        );
   261→      }
   262→
   263→      final step = _buildStep(context, i);
   264→
   265→      if (stepLabels != null && i < stepLabels!.length) {
   266→        children.add(
   267→          Row(
   268→            mainAxisSize: MainAxisSize.min,
   269→            children: [
   270→              step,
   271→              const SizedBox(width: 8),
   272→              Text(
   273→                stepLabels![i],
   274→                style: TextStyle(
   275→                  fontSize: 13,
   276→                  color: i == currentStep
   277→                      ? context.colors.text
   278→                      : context.colors.textMuted,
   279→                ),
   280→              ),
   281→            ],
   282→          ),
   283→        );
   284→      } else {
   285→        children.add(step);
   286→      }
   287→    }
   288→
   289→    return Column(
   290→      mainAxisSize: MainAxisSize.min,
   291→      crossAxisAlignment: CrossAxisAlignment.start,
   292→      children: children,
   293→    );
   294→  }
   295→
   296→  @override
   297→  Widget build(BuildContext context) {
   298→    Widget content;
   299→
   300→    switch (style) {
   301→      case OiStepperStyle.compact:
   302→        content = _buildCompact(context);
   303→      case OiStepperStyle.horizontal:
   304→        content = _buildHorizontal(context);
   305→      case OiStepperStyle.vertical:
   306→        content = _buildVertical(context);
