    92→  /// Creates an [OiRichContent] from plain text.
    93→  ///
    94→  /// Splits on double newlines to produce paragraph blocks. Single newlines
    95→  /// within a paragraph are preserved in the block text.
    96→  factory OiRichContent.fromPlainText(String text) {
    97→    if (text.isEmpty) return const OiRichContent();
    98→    final paragraphs = text.split(RegExp(r'\n\n+'));
    99→    return OiRichContent(
   100→      blocks: paragraphs
   101→          .map(
   102→            (p) => OiContentBlock(type: OiBlockType.paragraph, text: p.trim()),
   103→          )
   104→          .where((b) => b.text.isNotEmpty)
   105→          .toList(),
   106→    );
   107→  }
   108→
   109→  /// Creates empty content with a single empty paragraph block.
   110→  factory OiRichContent.empty() {
