   112→      blocks: [OiContentBlock(type: OiBlockType.paragraph, text: '')],
   113→    );
   114→  }
   115→
   116→  /// The content blocks.
   117→  final List<OiContentBlock> blocks;
   118→
   119→  /// Converts the content to an HTML string.
   120→  String toHtml() {
   121→    final buffer = StringBuffer();
   122→    var inOrderedList = false;
   123→    var inUnorderedList = false;
   124→
   125→    for (var i = 0; i < blocks.length; i++) {
   126→      final block = blocks[i];
   127→
   128→      // Close lists when block type changes.
   129→      if (block.type != OiBlockType.numberedList && inOrderedList) {
   130→        buffer.write('</ol>');
   131→        inOrderedList = false;
   132→      }
   133→      if (block.type != OiBlockType.bulletList && inUnorderedList) {
   134→        buffer.write('</ul>');
   135→        inUnorderedList = false;
   136→      }
   137→
   138→      switch (block.type) {
   139→        case OiBlockType.paragraph:
   140→          buffer.write('<p>${_escapeHtml(block.text)}</p>');
   141→        case OiBlockType.heading1:
   142→          buffer.write('<h1>${_escapeHtml(block.text)}</h1>');
   143→        case OiBlockType.heading2:
   144→          buffer.write('<h2>${_escapeHtml(block.text)}</h2>');
   145→        case OiBlockType.heading3:
   146→          buffer.write('<h3>${_escapeHtml(block.text)}</h3>');
   147→        case OiBlockType.bulletList:
   148→          if (!inUnorderedList) {
   149→            buffer.write('<ul>');
   150→            inUnorderedList = true;
   151→          }
   152→          buffer.write('<li>${_escapeHtml(block.text)}</li>');
   153→        case OiBlockType.numberedList:
   154→          if (!inOrderedList) {
   155→            buffer.write('<ol>');
   156→            inOrderedList = true;
   157→          }
   158→          buffer.write('<li>${_escapeHtml(block.text)}</li>');
   159→        case OiBlockType.code:
   160→          final lang = block.metadata?['language'] as String?;
   161→          if (lang != null && lang.isNotEmpty) {
   162→            buffer.write(
   163→              '<pre><code class="language-$lang">'
   164→              '${_escapeHtml(block.text)}'
   165→              '</code></pre>',
   166→            );
   167→          } else {
   168→            buffer.write(
   169→              '<pre><code>${_escapeHtml(block.text)}</code></pre>',
   170→            );
   171→          }
   172→        case OiBlockType.quote:
   173→          buffer.write(
   174→            '<blockquote>${_escapeHtml(block.text)}</blockquote>',
   175→          );
   176→        case OiBlockType.divider:
   177→          buffer.write('<hr/>');
   178→      }
   179→    }
   180→
   181→    // Close any open lists at the end.
   182→    if (inOrderedList) buffer.write('</ol>');
   183→    if (inUnorderedList) buffer.write('</ul>');
   184→
   185→    return buffer.toString();
   186→  }
   187→
   188→  /// Converts the content to a Markdown string.
   189→  String toMarkdown() {
   190→    final buffer = StringBuffer();
   191→    var numberedIndex = 0;
   192→    OiBlockType? prevType;
   193→
   194→    for (final block in blocks) {
   195→      // Reset numbered index when leaving a numbered list.
   196→      if (block.type != OiBlockType.numberedList &&
   197→          prevType == OiBlockType.numberedList) {
   198→        numberedIndex = 0;
   199→      }
   200→
   201→      if (prevType != null) buffer.writeln();
   202→
   203→      switch (block.type) {
   204→        case OiBlockType.paragraph:
   205→          buffer.write(block.text);
   206→        case OiBlockType.heading1:
   207→          buffer.write('# ${block.text}');
   208→        case OiBlockType.heading2:
   209→          buffer.write('## ${block.text}');
   210→        case OiBlockType.heading3:
   211→          buffer.write('### ${block.text}');
   212→        case OiBlockType.bulletList:
   213→          buffer.write('- ${block.text}');
   214→        case OiBlockType.numberedList:
   215→          numberedIndex++;
   216→          buffer.write('$numberedIndex. ${block.text}');
   217→        case OiBlockType.code:
   218→          final lang = block.metadata?['language'] as String? ?? '';
   219→          buffer.write('```$lang\n${block.text}\n```');
   220→        case OiBlockType.quote:
   221→          buffer.write('> ${block.text}');
   222→        case OiBlockType.divider:
   223→          buffer.write('---');
   224→      }
   225→
   226→      prevType = block.type;
   227→    }
   228→
   229→    return buffer.toString();
   230→  }
   231→
   232→  /// Converts the content to plain text, stripping all formatting.
   233→  String toPlainText() {
   234→    return blocks
   235→        .where((b) => b.type != OiBlockType.divider)
   236→        .map((b) => b.text)
   237→        .join('\n');
   238→  }
   239→
   240→  /// Returns the total word count across all blocks.
   241→  int get wordCount {
   242→    var count = 0;
   243→    for (final block in blocks) {
   244→      if (block.text.trim().isEmpty) continue;
   245→      count += block.text.trim().split(RegExp(r'\s+')).length;
   246→    }
   247→    return count;
   248→  }
   249→
   250→  @override
