   267→/// Controller for the rich editor.
   268→///
   269→/// Manages the [OiRichContent] and notifies listeners when the content
   270→/// changes. Provides convenience methods for inserting text and
   271→/// serialising the content.
   272→///
   273→/// {@category Composites}
   274→class OiRichEditorController extends ChangeNotifier {
   275→  /// Creates an [OiRichEditorController] with optional [initialContent].
   276→  OiRichEditorController({OiRichContent? initialContent})
   277→      : _content = initialContent ?? OiRichContent.empty();
   278→
   279→  OiRichContent _content;
   280→
   281→  /// The current content.
   282→  OiRichContent get content => _content;
   283→
   284→  /// Sets the content and notifies listeners.
   285→  set content(OiRichContent value) {
   286→    _content = value;
   287→    notifyListeners();
   288→  }
   289→
   290→  /// Inserts [text] at the end of the last block.
   291→  ///
   292→  /// If there are no blocks a new paragraph block is created.
   293→  void insertText(String text) {
   294→    final blocks = List<OiContentBlock>.from(_content.blocks);
   295→    if (blocks.isEmpty) {
   296→      blocks.add(OiContentBlock(type: OiBlockType.paragraph, text: text));
   297→    } else {
   298→      final last = blocks.last;
   299→      blocks[blocks.length - 1] = OiContentBlock(
   300→        type: last.type,
   301→        text: last.text + text,
   302→        metadata: last.metadata,
   303→      );
   304→    }
   305→    _content = OiRichContent(blocks: blocks);
   306→    notifyListeners();
   307→  }
   308→
   309→  /// Directly sets the content without triggering the setter's public
   310→  /// notification path. Used internally by the editor state to update
   311→  /// individual blocks without a redundant rebuild.
   312→  void updateContentSilently(OiRichContent value) {
   313→    _content = value;
   314→    notifyListeners();
   315→  }
   316→
   317→  /// Gets the content as HTML.
   318→  String toHtml() => _content.toHtml();
   319→
   320→  /// Gets the content as Markdown.
   321→  String toMarkdown() => _content.toMarkdown();
   322→
   323→  /// Gets the content as plain text.
   324→  String toPlainText() => _content.toPlainText();
   325→
   326→  /// Gets the word count.
   327→  int get wordCount => _content.wordCount;
   328→}
