   493→class _OiRichEditorState extends State<OiRichEditor> {
   494→  late FocusNode _focusNode;
   495→  bool _focused = false;
   496→
   497→  /// One controller per block — kept in sync with the model.
   498→  final List<TextEditingController> _blockControllers = [];
   499→
   500→  @override
   501→  void initState() {
   502→    super.initState();
   503→    _focusNode = FocusNode()
   504→      ..addListener(_handleFocusChange);
   505→    widget.controller.addListener(_handleContentChange);
   506→    _syncBlockControllers();
   507→    if (widget.autoFocus) {
   508→      _focusNode.requestFocus();
   509→    }
   510→  }
   511→
   512→  @override
   513→  void didUpdateWidget(OiRichEditor oldWidget) {
   514→    super.didUpdateWidget(oldWidget);
   515→    if (oldWidget.controller != widget.controller) {
   516→      oldWidget.controller.removeListener(_handleContentChange);
   517→      widget.controller.addListener(_handleContentChange);
   518→      _syncBlockControllers();
   519→    }
   520→  }
   521→
   522→  @override
   523→  void dispose() {
   524→    _focusNode
   525→      ..removeListener(_handleFocusChange)
   526→      ..dispose();
   527→    widget.controller.removeListener(_handleContentChange);
   528→    for (final c in _blockControllers) {
   529→      c.dispose();
   530→    }
   531→    super.dispose();
   532→  }
   533→
   534→  void _handleFocusChange() {
   535→    final focused = _focusNode.hasFocus;
   536→    if (focused != _focused) {
   537→      setState(() => _focused = focused);
   538→      widget.onFocusChange?.call(focused);
   539→    }
   540→  }
   541→
   542→  void _handleContentChange() {
   543→    _syncBlockControllers();
   544→    setState(() {});
   545→    widget.onChange?.call(widget.controller.content);
   546→  }
   547→
   548→  void _syncBlockControllers() {
   549→    final blocks = widget.controller.content.blocks;
   550→
   551→    // Dispose excess controllers.
   552→    while (_blockControllers.length > blocks.length) {
   553→      _blockControllers.removeLast().dispose();
   554→    }
   555→
   556→    // Add missing controllers.
   557→    while (_blockControllers.length < blocks.length) {
   558→      _blockControllers.add(TextEditingController());
   559→    }
   560→
   561→    // Sync text content.
   562→    for (var i = 0; i < blocks.length; i++) {
   563→      if (_blockControllers[i].text != blocks[i].text) {
   564→        _blockControllers[i].text = blocks[i].text;
   565→      }
   566→    }
   567→  }
