   569→  void _onBlockChanged(int index, String text) {
   570→    final blocks = List<OiContentBlock>.from(widget.controller.content.blocks);
   571→    if (index < blocks.length) {
   572→      blocks[index] = OiContentBlock(
   573→        type: blocks[index].type,
   574→        text: text,
   575→        metadata: blocks[index].metadata,
   576→      );
   577→      widget.controller.updateContentSilently(OiRichContent(blocks: blocks));
   578→    }
   579→  }
