   583→  TextStyle _styleForBlock(OiContentBlock block, BuildContext context) {
   584→    final themeData = OiTheme.maybeOf(context);
   585→    final textTheme = themeData?.textTheme;
   586→    final colors = themeData?.colors;
   587→
   588→    switch (block.type) {
   589→      case OiBlockType.heading1:
   590→        return textTheme?.styleFor(OiLabelVariant.h1) ??
   591→            const TextStyle(fontSize: 40, fontWeight: FontWeight.w700);
   592→      case OiBlockType.heading2:
   593→        return textTheme?.styleFor(OiLabelVariant.h2) ??
   594→            const TextStyle(fontSize: 32, fontWeight: FontWeight.w600);
   595→      case OiBlockType.heading3:
   596→        return textTheme?.styleFor(OiLabelVariant.h3) ??
