   600→            const TextStyle(fontSize: 14, fontFamily: 'monospace');
   601→      case OiBlockType.quote:
   602→        return (textTheme?.styleFor(OiLabelVariant.body) ??
   603→                const TextStyle(fontSize: 16))
   604→            .copyWith(
   605→          fontStyle: FontStyle.italic,
   606→          color: colors?.textMuted,
   607→        );
   608→      case OiBlockType.paragraph:
   609→      case OiBlockType.bulletList:
   610→      case OiBlockType.numberedList:
   611→      case OiBlockType.divider:
