   617→  Widget _buildBlock(
   618→    BuildContext context,
   619→    int index,
   620→    OiContentBlock block,
   621→  ) {
   622→    if (block.type == OiBlockType.divider) {
   623→      final colors = OiTheme.maybeOf(context)?.colors;
   624→      return Padding(
   625→        padding: const EdgeInsets.symmetric(vertical: 8),
