   629→        ),
   630→      );
   631→    }
   632→
   633→    final style = _styleForBlock(block, context);
   634→    final cursorColor =
   635→        OiTheme.maybeOf(context)?.colors.primary.base ?? const Color(0xFF000000);
   636→
   637→    Widget blockWidget = EditableText(
   638→      controller: _blockControllers[index],
   639→      focusNode: FocusNode(),
   640→      style: style,
   641→      cursorColor: cursorColor,
   642→      backgroundCursorColor: const Color(0xFF000000),
   643→      maxLines: null,
   644→      readOnly: widget.readOnly,
   645→      onChanged: (text) => _onBlockChanged(index, text),
   646→      selectionColor: cursorColor.withValues(alpha: 0.3),
   647→    );
   648→
   649→    // Add prefix for list items.
   650→    if (block.type == OiBlockType.bulletList) {
   651→      blockWidget = Row(
   652→        crossAxisAlignment: CrossAxisAlignment.start,
   653→        children: [
   654→          Text('\u2022 ', style: style),
   655→          Expanded(child: blockWidget),
   656→        ],
   657→      );
   658→    } else if (block.type == OiBlockType.numberedList) {
   659→      // Count the index within contiguous numbered blocks.
   660→      var num = 1;
   661→      for (var j = index - 1; j >= 0; j--) {
   662→        if (widget.controller.content.blocks[j].type ==
   663→            OiBlockType.numberedList) {
   664→          num++;
   665→        } else {
   666→          break;
   667→        }
   668→      }
   669→      blockWidget = Row(
   670→        crossAxisAlignment: CrossAxisAlignment.start,
   671→        children: [
   672→          Text('$num. ', style: style),
   673→          Expanded(child: blockWidget),
   674→        ],
   675→      );
   676→    } else if (block.type == OiBlockType.quote) {
   677→      final colors = OiTheme.maybeOf(context)?.colors;
   678→      blockWidget = Container(
   679→        decoration: BoxDecoration(
   680→          border: Border(
   681→            left: BorderSide(
   682→              color: colors?.border ?? const Color(0xFFD1D5DB),
   683→              width: 3,
   684→            ),
   685→          ),
   686→        ),
   687→        padding: const EdgeInsets.only(left: 12),
   688→        child: blockWidget,
   689→      );
   690→    } else if (block.type == OiBlockType.code) {
   691→      final colors = OiTheme.maybeOf(context)?.colors;
   692→      blockWidget = Container(
   693→        padding: const EdgeInsets.all(12),
   694→        decoration: BoxDecoration(
   695→          color: colors?.surfaceSubtle ?? const Color(0xFFF9FAFB),
   696→          borderRadius: BorderRadius.circular(6),
   697→        ),
   698→        child: blockWidget,
   699→      );
   700→    }
   701→
   702→    return Padding(
   703→      padding: const EdgeInsets.symmetric(vertical: 4),
   704→      child: blockWidget,
   705→    );
   706→  }
