   910→/// Escapes HTML special characters.
   911→String _escapeHtml(String text) {
   912→  return text
   913→      .replaceAll('&', '&amp;')
   914→      .replaceAll('<', '&lt;')
   915→      .replaceAll('>', '&gt;')
   916→      .replaceAll('"', '&quot;');
   917→}
   918→
   919→/// Compares two nullable maps for equality.
   920→bool _mapEquals(Map<String, dynamic>? a, Map<String, dynamic>? b) {
   921→  if (a == null && b == null) return true;
   922→  if (a == null || b == null) return false;
   923→  if (a.length != b.length) return false;
   924→  for (final key in a.keys) {
   925→    if (a[key] != b[key]) return false;
   926→  }
   927→  return true;
   928→}
