     4→/// Wraps a list of focusable children and enables arrow key navigation.
     5→///
     6→/// This is a behavior widget, not visual. It manages the [highlightedIndex]
     7→/// and fires callbacks. The visual highlighting is done by the consumer
     8→/// widget based on the index.
     9→///
    10→/// Used by [OiSelect], [OiComboBox], [OiCommandBar], [OiContextMenu],
    11→/// [OiTable], [OiTree], and any widget with keyboard-navigable lists.
    12→///
    13→/// {@category Composites}
    14→class OiArrowNav extends StatefulWidget {
    15→  /// Creates an [OiArrowNav].
    16→  const OiArrowNav({
    17→    required this.child,
    18→    required this.itemCount,
    19→    super.key,
    20→    this.highlightedIndex,
    21→    this.onHighlightChange,
    22→    this.onSelect,
    23→    this.onEscape,
    24→    this.direction = Axis.vertical,
    25→    this.loop = true,
    26→    this.typeAhead = false,
    27→    this.enabled = true,
    28→  });
    29→
    30→  /// The widget subtree that contains the navigable items.
    31→  final Widget child;
    32→
    33→  /// The total number of items available for navigation.
    34→  ///
    35→  /// When zero, all keyboard handling is effectively a no-op.
    36→  final int itemCount;
    37→
    38→  /// The currently highlighted item index.
    39→  ///
    40→  /// When `null`, no item is highlighted. Arrow key presses will start
    41→  /// from index 0 (down/right) or the last index (up/left).
    42→  final int? highlightedIndex;
    43→
    44→  /// Called when the highlighted index changes due to arrow key input.
    45→  final ValueChanged<int>? onHighlightChange;
    46→
    47→  /// Called when the user presses Enter to select the highlighted item.
    48→  ///
    49→  /// Receives the current [highlightedIndex]. Not called when no item
    50→  /// is highlighted.
    51→  final ValueChanged<int>? onSelect;
    52→
    53→  /// Called when the user presses the Escape key.
    54→  final VoidCallback? onEscape;
    55→
    56→  /// The navigation axis.
    57→  ///
    58→  /// [Axis.vertical] listens for Up/Down arrows; [Axis.horizontal] listens
    59→  /// for Left/Right arrows. Defaults to [Axis.vertical].
    60→  final Axis direction;
    61→
    62→  /// Whether navigation wraps around at the ends of the list.
    63→  ///
    64→  /// When `true` (the default), pressing down on the last item moves to the
    65→  /// first, and pressing up on the first item moves to the last.
    66→  final bool loop;
    67→
    68→  /// Whether type-ahead character matching is enabled.
    69→  ///
    70→  /// When `true`, typing a character will jump to the next item whose label
    71→  /// starts with that character. Currently reserved for future implementation.
    72→  final bool typeAhead;
    73→
    74→  /// Whether keyboard handling is active.
    75→  ///
    76→  /// When `false`, all key events are ignored and passed through.
    77→  final bool enabled;
    78→
    79→  @override
    80→  State<OiArrowNav> createState() => _OiArrowNavState();
    81→}
    82→
    83→class _OiArrowNavState extends State<OiArrowNav> {
    84→  // ── Key handling ──────────────────────────────────────────────────────────
    85→
    86→  /// Returns the logical key that moves to the next item.
    87→  LogicalKeyboardKey get _nextKey => widget.direction == Axis.vertical
    88→      ? LogicalKeyboardKey.arrowDown
    89→      : LogicalKeyboardKey.arrowRight;
    90→
    91→  /// Returns the logical key that moves to the previous item.
    92→  LogicalKeyboardKey get _prevKey => widget.direction == Axis.vertical
    93→      ? LogicalKeyboardKey.arrowUp
    94→      : LogicalKeyboardKey.arrowLeft;
    95→
    96→  /// Handles key events for arrow navigation, Enter, and Escape.
    97→  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
    98→    if (!widget.enabled) return KeyEventResult.ignored;
    99→    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
   100→      return KeyEventResult.ignored;
   101→    }
   102→
   103→    final key = event.logicalKey;
   104→
   105→    // ── Escape ────────────────────────────────────────────────────────────
   106→    if (key == LogicalKeyboardKey.escape) {
   107→      widget.onEscape?.call();
   108→      return KeyEventResult.handled;
   109→    }
   110→
   111→    // ── Enter / Select ────────────────────────────────────────────────────
   112→    if (key == LogicalKeyboardKey.enter ||
   113→        key == LogicalKeyboardKey.numpadEnter) {
   114→      if (widget.highlightedIndex != null && widget.itemCount > 0) {
   115→        widget.onSelect?.call(widget.highlightedIndex!);
   116→      }
   117→      return KeyEventResult.handled;
   118→    }
   119→
   120→    // ── Arrow keys ────────────────────────────────────────────────────────
   121→    if (key == _nextKey) {
   122→      _moveNext();
   123→      return KeyEventResult.handled;
   124→    }
   125→
   126→    if (key == _prevKey) {
   127→      _movePrev();
   128→      return KeyEventResult.handled;
   129→    }
   130→
   131→    return KeyEventResult.ignored;
   132→  }
   133→
   134→  /// Moves the highlight to the next item.
   135→  void _moveNext() {
   136→    if (widget.itemCount == 0) return;
   137→
   138→    final current = widget.highlightedIndex;
   139→
   140→    if (current == null) {
   141→      widget.onHighlightChange?.call(0);
   142→      return;
   143→    }
   144→
   145→    if (current >= widget.itemCount - 1) {
   146→      // At the end.
   147→      if (widget.loop) {
   148→        widget.onHighlightChange?.call(0);
   149→      }
   150→      // When loop is false, do nothing at the boundary.
   151→      return;
   152→    }
   153→
   154→    widget.onHighlightChange?.call(current + 1);
   155→  }
   156→
   157→  /// Moves the highlight to the previous item.
   158→  void _movePrev() {
   159→    if (widget.itemCount == 0) return;
   160→
   161→    final current = widget.highlightedIndex;
   162→
   163→    if (current == null) {
   164→      widget.onHighlightChange?.call(widget.itemCount - 1);
   165→      return;
   166→    }
   167→
   168→    if (current <= 0) {
   169→      // At the beginning.
   170→      if (widget.loop) {
   171→        widget.onHighlightChange?.call(widget.itemCount - 1);
   172→      }
   173→      // When loop is false, do nothing at the boundary.
   174→      return;
   175→    }
   176→
   177→    widget.onHighlightChange?.call(current - 1);
   178→  }
   179→
   180→  // ── Build ─────────────────────────────────────────────────────────────────
   181→
   182→  @override
   183→  Widget build(BuildContext context) {
   184→    return Focus(
   185→      autofocus: true,
   186→      onKeyEvent: _handleKeyEvent,
   187→      child: widget.child,
   188→    );
   189→  }
   190→}
