   155→class _OiNavMenuBodyState extends State<_OiNavMenuBody> {
   156→  int _focusedIndex = -1;
   157→  late FocusNode _focusNode;
   158→
   159→  @override
   160→  void initState() {
   161→    super.initState();
   162→    _focusNode = FocusNode();
   163→  }
   164→
   165→  @override
   166→  void dispose() {
   167→    _focusNode.dispose();
   168→    super.dispose();
   169→  }
   170→
   171→  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
   172→    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
   173→      return KeyEventResult.ignored;
   174→    }
   175→
   176→    final key = event.logicalKey;
   177→
   178→    if (key == LogicalKeyboardKey.arrowDown) {
   179→      _moveFocus(1);
   180→      return KeyEventResult.handled;
   181→    }
   182→    if (key == LogicalKeyboardKey.arrowUp) {
   183→      _moveFocus(-1);
   184→      return KeyEventResult.handled;
   185→    }
   186→    if (key == LogicalKeyboardKey.enter ||
   187→        key == LogicalKeyboardKey.numpadEnter) {
   188→      if (_focusedIndex >= 0 && _focusedIndex < widget.items.length) {
   189→        final item = widget.items[_focusedIndex];
   190→        if (!item.disabled) {
   191→          widget.onSelect(item.id);
   192→        }
   193→      }
   194→      return KeyEventResult.handled;
   195→    }
   196→
   197→    return KeyEventResult.ignored;
   198→  }
   199→
   200→  void _moveFocus(int delta) {
   201→    if (widget.items.isEmpty) return;
   202→    var next = _focusedIndex + delta;
   203→    while (next >= 0 && next < widget.items.length && widget.items[next].disabled) {
   204→      next += delta;
   205→    }
   206→    if (next >= 0 && next < widget.items.length) {
   207→      setState(() => _focusedIndex = next);
   208→    }
   209→  }
   210→
   211→  @override
   212→  Widget build(BuildContext context) {
   213→    return Focus(
   214→      focusNode: _focusNode,
   215→      onKeyEvent: _handleKeyEvent,
   216→      child: Column(
   217→        crossAxisAlignment: CrossAxisAlignment.stretch,
   218→        mainAxisSize: MainAxisSize.min,
   219→        children: [
   220→          if (widget.header != null) widget.header!,
   221→          for (var i = 0; i < widget.items.length; i++)
   222→            _buildItem(context, widget.items[i], i),
   223→          if (widget.footer != null) widget.footer!,
   224→        ],
   225→      ),
   226→    );
   227→  }
   228→
   229→  Widget _buildItem(BuildContext context, OiNavMenuItem item, int index) {
   230→    final colors = context.colors;
   231→    final isSelected = item.id == widget.selectedId;
   232→    final isFocused = index == _focusedIndex;
   233→
   234→    Color bg;
   235→    if (isSelected) {
   236→      bg = colors.primary.base.withValues(alpha: 0.1);
   237→    } else if (isFocused) {
   238→      bg = colors.surfaceHover;
   239→    } else {
   240→      bg = const Color(0x00000000);
   241→    }
   242→
   243→    final textColor = isSelected
   244→        ? colors.primary.base
   245→        : item.disabled
   246→            ? colors.textMuted
   247→            : colors.text;
   248→
   249→    final iconColor = item.color ?? (isSelected ? colors.primary.base : colors.textSubtle);
   250→
   251→    Widget row = Container(
   252→      color: bg,
   253→      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
   254→      child: Row(
   255→        children: [
   256→          if (item.icon != null) ...[
   257→            Icon(item.icon, size: 18, color: item.disabled ? colors.textMuted : iconColor),
   258→            const SizedBox(width: 10),
   259→          ],
   260→          Expanded(
   261→            child: Text(
   262→              item.label,
   263→              style: TextStyle(
   264→                fontSize: 14,
   265→                fontWeight: isSelected ? FontWeight.w600 : FontWeight.w400,
   266→                color: textColor,
   267→              ),
   268→              maxLines: 1,
   269→              overflow: TextOverflow.ellipsis,
   270→            ),
   271→          ),
   272→          if (item.badgeCount != null && item.badgeCount! > 0)
   273→            OiBadge(
   274→              label: item.badgeCount.toString(),
   275→              size: OiBadgeSize.small,
   276→            ),
   277→        ],
   278→      ),
   279→    );
   280→
   281→    row = OiTappable(
   282→      enabled: !item.disabled,
   283→      semanticLabel: item.label,
   284→      onTap: () => widget.onSelect(item.id),
   285→      child: row,
   286→    );
   287→
   288→    if (widget.contextMenu != null) {
   289→      row = OiContextMenu(
   290→        items: widget.contextMenu!(item),
   291→        child: row,
   292→      );
   293→    }
   294→
   295→    return row;
   296→  }
   297→}
