     6→// ── Shortcut activator ──────────────────────────────────────────────────────
     7→
     8→/// Platform-aware keyboard shortcut activator.
     9→///
    10→/// Automatically maps [LogicalKeyboardKey] modifiers:
    11→/// - `Ctrl` maps to `Cmd` on macOS/iOS
    12→/// - `Ctrl` stays `Ctrl` on Windows/Linux/Web
    13→///
    14→/// {@category Composites}
    15→class OiShortcutActivator extends SingleActivator {
    16→  /// Creates an [OiShortcutActivator] with explicit modifier flags.
    17→  ///
    18→  /// Prefer [OiShortcutActivator.primary] for platform-adaptive shortcuts.
    19→  const OiShortcutActivator(
    20→    super.trigger, {
    21→    super.control,
    22→    super.shift,
    23→    super.alt,
    24→    super.meta,
    25→  });
    26→
    27→  /// Creates a shortcut using the primary modifier (Ctrl/Cmd).
    28→  ///
    29→  /// On macOS and iOS the primary modifier is `Cmd` (meta); on all other
    30→  /// platforms it is `Ctrl` (control).
    31→  factory OiShortcutActivator.primary(
    32→    LogicalKeyboardKey key, {
    33→    bool shift = false,
    34→    bool alt = false,
    35→  }) {
    36→    final useMeta = _isApplePlatform;
    37→    return OiShortcutActivator(
    38→      key,
    39→      control: !useMeta,
    40→      meta: useMeta,
    41→      shift: shift,
    42→      alt: alt,
    43→    );
    44→  }
    45→
    46→  /// Whether the current platform uses Cmd instead of Ctrl.
    47→  static bool get _isApplePlatform {
    48→    if (kIsWeb) return false;
    49→    return defaultTargetPlatform == TargetPlatform.macOS ||
    50→        defaultTargetPlatform == TargetPlatform.iOS;
    51→  }
    52→
    53→  /// Human-readable display label for this shortcut.
    54→  ///
    55→  /// Returns a platform-appropriate string such as `"Cmd+Z"` on macOS or
    56→  /// `"Ctrl+Z"` on other platforms.
    57→  String get displayLabel {
    58→    final parts = <String>[];
    59→
    60→    if (control) {
    61→      parts.add(_isApplePlatform ? 'Ctrl' : 'Ctrl');
    62→    }
    63→    if (meta) {
    64→      parts.add(_isApplePlatform ? 'Cmd' : 'Meta');
    65→    }
    66→    if (alt) {
    67→      parts.add(_isApplePlatform ? 'Opt' : 'Alt');
    68→    }
    69→    if (shift) {
    70→      parts.add('Shift');
    71→    }
    72→
    73→    parts.add(_keyLabel(trigger));
    74→
    75→    return parts.join('+');
    76→  }
    77→
    78→  /// Returns a short human-readable label for a [LogicalKeyboardKey].
    79→  static String _keyLabel(LogicalKeyboardKey key) {
    80→    // Map well-known keys to concise labels.
    81→    if (key == LogicalKeyboardKey.delete) return 'Del';
    82→    if (key == LogicalKeyboardKey.backspace) return 'Backspace';
    83→    if (key == LogicalKeyboardKey.enter) return 'Enter';
    84→    if (key == LogicalKeyboardKey.escape) return 'Esc';
    85→    if (key == LogicalKeyboardKey.tab) return 'Tab';
    86→    if (key == LogicalKeyboardKey.space) return 'Space';
    87→    if (key == LogicalKeyboardKey.arrowUp) return 'Up';
    88→    if (key == LogicalKeyboardKey.arrowDown) return 'Down';
    89→    if (key == LogicalKeyboardKey.arrowLeft) return 'Left';
    90→    if (key == LogicalKeyboardKey.arrowRight) return 'Right';
    91→
    92→    // Fall back to the key label, uppercased for single characters.
    93→    final label = key.keyLabel;
    94→    if (label.length == 1) return label.toUpperCase();
    95→    return label;
    96→  }
    97→}
