    17→  /// Creates an [OiSidebarSection].
    18→  const OiSidebarSection({
    19→    required this.items,
    20→    this.title,
    21→    this.collapsible = true,
    22→  });
    23→
    24→  /// The optional header title for this section.
    25→  ///
    26→  /// When `null` no header is rendered and the items appear without a
    27→  /// visual grouping label.
