    79→
    80→// ── Display mode ─────────────────────────────────────────────────────────────
    81→
    82→/// The display mode of the sidebar.
    83→///
    84→/// {@category Composites}
    85→enum OiSidebarMode {
    86→  /// Shows icons and labels (default ~260px wide).
    87→  full,
    88→
    89→  /// Shows only icons with tooltips (~64px wide).
    90→  compact,
    91→
    92→  /// Not visible.
