    95→
    96→// ── OiSidebar ────────────────────────────────────────────────────────────────
    97→
    98→/// The main application sidebar with collapsible sections and nested items.
    99→///
   100→/// Supports three modes:
   101→/// - [OiSidebarMode.full]: Shows icons and labels (default ~260px wide)
   102→/// - [OiSidebarMode.compact]: Shows only icons with tooltips (~64px wide)
   103→/// - [OiSidebarMode.hidden]: Not visible
   104→///
   105→/// The sidebar supports:
   106→/// - Collapsible sections with optional titles
   107→/// - Nested items with indentation
   108→/// - Badge counts on items
   109→/// - Keyboard navigation with arrow keys and Enter
   110→/// - Accessible semantics with a navigation role
   111→/// - Optional header and footer widgets
   112→/// - Optional resizable width
   113→///
   114→/// {@category Composites}
   115→class OiSidebar extends StatefulWidget {
   116→  /// Creates an [OiSidebar].
   117→  const OiSidebar({
   118→    required this.sections,
   119→    required this.selectedId,
   120→    required this.onSelect,
   121→    required this.label,
   122→    this.mode = OiSidebarMode.full,
   123→    this.width = 260,
   124→    this.compactWidth = 64,
   125→    this.resizable = false,
   126→    this.header,
   127→    this.footer,
   128→    super.key,
   129→  });
   130→
   131→  /// The sections containing navigation items.
   132→  final List<OiSidebarSection> sections;
   133→
   134→  /// The [OiSidebarItem.id] of the currently selected item.
   135→  ///
   136→  /// When `null` no item is highlighted as selected.
   137→  final String? selectedId;
   138→
   139→  /// Called when the user selects an item.
   140→  final ValueChanged<String> onSelect;
   141→
   142→  /// The accessibility label for the sidebar navigation landmark.
   143→  final String label;
   144→
   145→  /// The display mode controlling visibility and width.
   146→  final OiSidebarMode mode;
   147→
   148→  /// The width in logical pixels when [mode] is [OiSidebarMode.full].
   149→  final double width;
   150→
   151→  /// The width in logical pixels when [mode] is [OiSidebarMode.compact].
   152→  final double compactWidth;
   153→
   154→  /// Whether the sidebar edge can be dragged to resize.
   155→  final bool resizable;
   156→
   157→  /// An optional widget rendered above the navigation items.
   158→  final Widget? header;
   159→
   160→  /// An optional widget rendered below the navigation items.
   161→  final Widget? footer;
   162→
   163→  @override
   164→  State<OiSidebar> createState() => _OiSidebarState();
   165→}
   166→
   167→class _OiSidebarState extends State<OiSidebar> {
   168→  final Set<String> _collapsedSections = {};
   169→  final Set<String> _expandedParents = {};
   170→  int _focusedIndex = -1;
   171→  late FocusNode _focusNode;
   172→
   173→  /// Flattened list of all visible item ids for keyboard navigation.
   174→  List<_FlatItem> _flatItems = [];
   175→
   176→  @override
   177→  void initState() {
   178→    super.initState();
   179→    _focusNode = FocusNode();
   180→    _rebuildFlatItems();
   181→  }
   182→
   183→  @override
   184→  void didUpdateWidget(OiSidebar oldWidget) {
   185→    super.didUpdateWidget(oldWidget);
   186→    _rebuildFlatItems();
   187→  }
   188→
   189→  @override
   190→  void dispose() {
   191→    _focusNode.dispose();
   192→    super.dispose();
   193→  }
   194→
   195→  void _rebuildFlatItems() {
   196→    final items = <_FlatItem>[];
   197→    for (var si = 0; si < widget.sections.length; si++) {
   198→      final section = widget.sections[si];
   199→      final sectionKey = section.title ?? 'section_$si';
   200→      if (_collapsedSections.contains(sectionKey)) continue;
   201→      for (final item in section.items) {
   202→        items.add(_FlatItem(item: item, depth: 0));
   203→        if (item.children != null && _expandedParents.contains(item.id)) {
   204→          for (final child in item.children!) {
   205→            items.add(_FlatItem(item: child, depth: 1));
   206→          }
   207→        }
   208→      }
   209→    }
   210→    _flatItems = items;
   211→  }
   212→
   213→  KeyEventResult _handleKeyEvent(FocusNode node, KeyEvent event) {
   214→    if (event is! KeyDownEvent && event is! KeyRepeatEvent) {
   215→      return KeyEventResult.ignored;
   216→    }
   217→
   218→    final key = event.logicalKey;
   219→
   220→    if (key == LogicalKeyboardKey.arrowDown) {
   221→      _moveFocus(1);
   222→      return KeyEventResult.handled;
   223→    }
   224→    if (key == LogicalKeyboardKey.arrowUp) {
   225→      _moveFocus(-1);
   226→      return KeyEventResult.handled;
   227→    }
   228→    if (key == LogicalKeyboardKey.enter ||
   229→        key == LogicalKeyboardKey.numpadEnter) {
   230→      if (_focusedIndex >= 0 && _focusedIndex < _flatItems.length) {
   231→        final fi = _flatItems[_focusedIndex];
   232→        if (!fi.item.disabled) {
   233→          widget.onSelect(fi.item.id);
   234→        }
   235→      }
   236→      return KeyEventResult.handled;
   237→    }
   238→
   239→    return KeyEventResult.ignored;
   240→  }
   241→
   242→  void _moveFocus(int delta) {
   243→    if (_flatItems.isEmpty) return;
   244→    var next = _focusedIndex + delta;
   245→    // Skip disabled items.
   246→    while (next >= 0 && next < _flatItems.length && _flatItems[next].item.disabled) {
   247→      next += delta;
   248→    }
   249→    if (next >= 0 && next < _flatItems.length) {
   250→      setState(() => _focusedIndex = next);
   251→    }
   252→  }
   253→
   254→  void _toggleSection(String sectionKey) {
   255→    setState(() {
   256→      if (_collapsedSections.contains(sectionKey)) {
   257→        _collapsedSections.remove(sectionKey);
   258→      } else {
   259→        _collapsedSections.add(sectionKey);
   260→      }
   261→      _rebuildFlatItems();
   262→    });
   263→  }
   264→
   265→  void _toggleParent(String parentId) {
   266→    setState(() {
   267→      if (_expandedParents.contains(parentId)) {
   268→        _expandedParents.remove(parentId);
   269→      } else {
   270→        _expandedParents.add(parentId);
   271→      }
   272→      _rebuildFlatItems();
   273→    });
   274→  }
   275→
   276→  // ── Build ──────────────────────────────────────────────────────────────────
   277→
   278→  @override
   279→  Widget build(BuildContext context) {
   280→    if (widget.mode == OiSidebarMode.hidden) {
   281→      return const SizedBox.shrink();
   282→    }
   283→
   284→    final isCompact = widget.mode == OiSidebarMode.compact;
   285→    final effectiveWidth = isCompact ? widget.compactWidth : widget.width;
   286→
   287→    return Semantics(
   288→      label: widget.label,
   289→      explicitChildNodes: true,
   290→      child: Focus(
   291→        focusNode: _focusNode,
   292→        onKeyEvent: _handleKeyEvent,
   293→        child: SizedBox(
   294→          width: effectiveWidth,
   295→          child: Column(
   296→            crossAxisAlignment: CrossAxisAlignment.stretch,
   297→            children: [
   298→              if (widget.header != null) widget.header!,
   299→              Expanded(
   300→                child: SingleChildScrollView(
   301→                  child: Column(
   302→                    crossAxisAlignment: CrossAxisAlignment.stretch,
   303→                    children: _buildSections(context, isCompact),
   304→                  ),
   305→                ),
   306→              ),
   307→              if (widget.footer != null) widget.footer!,
   308→            ],
   309→          ),
   310→        ),
   311→      ),
   312→    );
   313→  }
   314→
   315→  List<Widget> _buildSections(BuildContext context, bool isCompact) {
   316→    final widgets = <Widget>[];
   317→    for (var si = 0; si < widget.sections.length; si++) {
   318→      final section = widget.sections[si];
   319→      final sectionKey = section.title ?? 'section_$si';
   320→      final isCollapsed = _collapsedSections.contains(sectionKey);
   321→
   322→      // Section header.
   323→      if (section.title != null && !isCompact) {
   324→        widgets.add(_buildSectionHeader(context, section, sectionKey, isCollapsed));
   325→      }
   326→
   327→      // Items.
   328→      if (!isCollapsed) {
   329→        for (final item in section.items) {
   330→          widgets.add(_buildItem(context, item, 0, isCompact));
   331→          if (item.children != null && _expandedParents.contains(item.id)) {
   332→            for (final child in item.children!) {
   333→              widgets.add(_buildItem(context, child, 1, isCompact));
   334→            }
   335→          }
   336→        }
   337→      }
   338→    }
   339→    return widgets;
   340→  }
   341→
   342→  Widget _buildSectionHeader(
   343→    BuildContext context,
   344→    OiSidebarSection section,
   345→    String sectionKey,
   346→    bool isCollapsed,
   347→  ) {
   348→    final colors = context.colors;
   349→    Widget header = Padding(
   350→      padding: const EdgeInsets.fromLTRB(16, 16, 16, 4),
   351→      child: Text(
   352→        section.title!,
   353→        style: TextStyle(
   354→          fontSize: 11,
   355→          fontWeight: FontWeight.w600,
   356→          letterSpacing: 1.5,
   357→          color: colors.textMuted,
   358→        ),
   359→      ),
   360→    );
   361→
   362→    if (section.collapsible) {
   363→      header = GestureDetector(
   364→        onTap: () => _toggleSection(sectionKey),
   365→        behavior: HitTestBehavior.opaque,
   366→        child: header,
   367→      );
   368→    }
   369→
   370→    return header;
   371→  }
   372→
   373→  Widget _buildItem(
   374→    BuildContext context,
   375→    OiSidebarItem item,
   376→    int depth,
   377→    bool isCompact,
   378→  ) {
   379→    final colors = context.colors;
   380→    final isSelected = item.id == widget.selectedId;
   381→    final hasChildren = item.children != null && item.children!.isNotEmpty;
   382→    final isExpanded = _expandedParents.contains(item.id);
   383→
   384→    // Determine the flat index for keyboard focus styling.
   385→    final flatIndex = _flatItems.indexWhere((fi) => fi.item.id == item.id);
   386→    final isFocused = flatIndex == _focusedIndex;
   387→
   388→    Color bg;
   389→    if (isSelected) {
   390→      bg = colors.primary.base.withValues(alpha: 0.1);
   391→    } else if (isFocused) {
   392→      bg = colors.surfaceHover;
   393→    } else {
   394→      bg = const Color(0x00000000);
   395→    }
   396→
   397→    final textColor = isSelected
   398→        ? colors.primary.base
   399→        : item.disabled
   400→            ? colors.textMuted
   401→            : colors.text;
   402→
   403→    final iconColor = isSelected
   404→        ? colors.primary.base
   405→        : item.disabled
   406→            ? colors.textMuted
   407→            : colors.textSubtle;
   408→
   409→    if (isCompact) {
   410→      return _buildCompactItem(context, item, bg, iconColor, isSelected);
   411→    }
   412→
   413→    // Full mode.
   414→    final indent = depth * 24.0;
   415→
   416→    final Widget content = Container(
   417→      color: bg,
   418→      padding: EdgeInsets.only(
   419→        left: 12 + indent,
   420→        right: 12,
   421→        top: 8,
   422→        bottom: 8,
   423→      ),
   424→      child: Row(
   425→        children: [
   426→          Icon(item.icon, size: 20, color: iconColor),
   427→          const SizedBox(width: 10),
   428→          Expanded(
   429→            child: Text(
   430→              item.label,
   431→              style: TextStyle(
   432→                fontSize: 14,
   433→                fontWeight: isSelected ? FontWeight.w600 : FontWeight.w400,
   434→                color: textColor,
   435→              ),
   436→              maxLines: 1,
   437→              overflow: TextOverflow.ellipsis,
   438→            ),
   439→          ),
   440→          if (item.badgeCount != null && item.badgeCount! > 0)
   441→            OiBadge(
   442→              label: item.badgeCount.toString(),
   443→              size: OiBadgeSize.small,
   444→            ),
   445→          if (hasChildren)
   446→            Padding(
   447→              padding: const EdgeInsets.only(left: 4),
   448→              child: Text(
   449→                isExpanded ? '\u25BC' : '\u25B6',
   450→                style: TextStyle(fontSize: 10, color: colors.textMuted),
   451→              ),
   452→            ),
   453→        ],
   454→      ),
   455→    );
   456→
   457→    return OiTappable(
   458→      enabled: !item.disabled,
   459→      semanticLabel: item.label,
   460→      onTap: () {
   461→        if (hasChildren) {
   462→          _toggleParent(item.id);
   463→        }
   464→        widget.onSelect(item.id);
   465→      },
   466→      child: content,
   467→    );
   468→  }
   469→
   470→  Widget _buildCompactItem(
   471→    BuildContext context,
   472→    OiSidebarItem item,
   473→    Color bg,
   474→    Color iconColor,
   475→    bool isSelected,
   476→  ) {
   477→    Widget icon = Container(
   478→      color: bg,
   479→      width: widget.compactWidth,
   480→      height: 48,
   481→      alignment: Alignment.center,
   482→      child: Stack(
   483→        clipBehavior: Clip.none,
   484→        children: [
   485→          Icon(item.icon, size: 24, color: iconColor),
   486→          if (item.badgeCount != null && item.badgeCount! > 0)
   487→            Positioned(
   488→              top: -4,
   489→              right: -8,
   490→              child: OiBadge(
   491→                label: item.badgeCount.toString(),
   492→                size: OiBadgeSize.small,
   493→              ),
   494→            ),
   495→        ],
   496→      ),
   497→    );
   498→
   499→    return OiTooltip(
   500→      message: item.label,
   501→      child: OiTappable(
   502→        enabled: !item.disabled,
   503→        semanticLabel: item.label,
   504→        onTap: () => widget.onSelect(item.id),
   505→        child: icon,
   506→      ),
   507→    );
   508→  }
   509→}
   510→
   511→/// A flattened sidebar item with its nesting depth for keyboard navigation.
   512→class _FlatItem {
   513→  const _FlatItem({required this.item, required this.depth});
   514→
   515→  /// The sidebar item.
   516→  final OiSidebarItem item;
   517→
   518→  /// The nesting depth (0 for top-level, 1 for children).
   519→  final int depth;
   520→}
