     3→/// Highlights a single widget by dimming everything else.
     4→///
     5→/// Renders an overlay with a transparent cutout around the [target] widget.
     6→/// Used for single-step highlighting and as a building block for [OiTour].
     7→///
     8→/// {@category Composites}
     9→class OiSpotlight extends StatefulWidget {
    10→  /// Creates an [OiSpotlight].
    11→  const OiSpotlight({
    12→    required this.target,
    13→    required this.child,
    14→    this.active = true,
    15→    this.overlayColor,
    16→    this.padding = 8,
    17→    this.borderRadius,
    18→    this.onTapOutside,
    19→    super.key,
    20→  });
    21→
    22→  /// The [GlobalKey] of the widget to spotlight.
    23→  final GlobalKey target;
    24→
    25→  /// The child widget tree (the full page content).
    26→  final Widget child;
    27→
    28→  /// Whether the spotlight overlay is active.
    29→  ///
    30→  /// When `false`, only [child] is rendered with no overlay.
    31→  final bool active;
    32→
    33→  /// The color of the dimmed overlay.
    34→  ///
    35→  /// Defaults to black54.
    36→  final Color? overlayColor;
    37→
    38→  /// Padding in logical pixels around the spotlighted widget.
    39→  final double padding;
    40→
    41→  /// Border radius of the cutout.
    42→  ///
    43→  /// When `null`, the cutout is a plain rectangle.
    44→  final BorderRadius? borderRadius;
    45→
    46→  /// Called when the user taps outside the spotlighted area.
    47→  final VoidCallback? onTapOutside;
    48→
    49→  @override
    50→  State<OiSpotlight> createState() => _OiSpotlightState();
    51→}
    52→
    53→class _OiSpotlightState extends State<OiSpotlight> {
    54→  Rect? _targetRect;
    55→
    56→  @override
    57→  void initState() {
    58→    super.initState();
    59→    if (widget.active) {
    60→      WidgetsBinding.instance.addPostFrameCallback((_) {
    61→        _updateTargetRect();
    62→      });
    63→    }
    64→  }
    65→
    66→  @override
    67→  void didUpdateWidget(OiSpotlight oldWidget) {
    68→    super.didUpdateWidget(oldWidget);
    69→    if (widget.active &&
    70→        (!oldWidget.active || widget.target != oldWidget.target)) {
    71→      WidgetsBinding.instance.addPostFrameCallback((_) {
    72→        _updateTargetRect();
    73→      });
    74→    }
    75→  }
    76→
    77→  void _updateTargetRect() {
    78→    final renderObject = widget.target.currentContext?.findRenderObject();
    79→    if (renderObject is RenderBox && renderObject.hasSize) {
    80→      final offset = renderObject.localToGlobal(Offset.zero);
    81→      final size = renderObject.size;
    82→      if (mounted) {
    83→        setState(() {
    84→          _targetRect = Rect.fromLTWH(
    85→            offset.dx - widget.padding,
    86→            offset.dy - widget.padding,
    87→            size.width + widget.padding * 2,
    88→            size.height + widget.padding * 2,
    89→          );
    90→        });
    91→      }
    92→    }
    93→  }
    94→
    95→  @override
    96→  Widget build(BuildContext context) {
    97→    if (!widget.active) {
    98→      return widget.child;
    99→    }
   100→
   101→    return Stack(
   102→      children: [
   103→        widget.child,
   104→        if (_targetRect != null)
   105→          Positioned.fill(
   106→            child: GestureDetector(
   107→              behavior: HitTestBehavior.opaque,
   108→              onTap: widget.onTapOutside,
   109→              child: CustomPaint(
   110→                key: const Key('oi_spotlight_overlay'),
   111→                painter: _SpotlightPainter(
   112→                  targetRect: _targetRect!,
   113→                  overlayColor:
   114→                      widget.overlayColor ?? const Color(0x8A000000),
   115→                  borderRadius: widget.borderRadius,
   116→                ),
   117→              ),
   118→            ),
   119→          ),
   120→      ],
   121→    );
   122→  }
   123→}
   124→
   125→/// Paints a dimmed overlay with a transparent cutout around [targetRect].
   126→class _SpotlightPainter extends CustomPainter {
   127→  const _SpotlightPainter({
   128→    required this.targetRect,
   129→    required this.overlayColor,
   130→    this.borderRadius,
   131→  });
   132→
   133→  final Rect targetRect;
   134→  final Color overlayColor;
   135→  final BorderRadius? borderRadius;
   136→
   137→  @override
   138→  void paint(Canvas canvas, Size size) {
   139→    final fullRect = Offset.zero & size;
   140→
   141→    final cutoutPath = Path();
   142→    if (borderRadius != null) {
   143→      cutoutPath.addRRect(borderRadius!.toRRect(targetRect));
   144→    } else {
   145→      cutoutPath.addRect(targetRect);
   146→    }
   147→
   148→    final overlayPath = Path.combine(
   149→      PathOperation.difference,
   150→      Path()..addRect(fullRect),
   151→      cutoutPath,
   152→    );
   153→
   154→    canvas.drawPath(
   155→      overlayPath,
   156→      Paint()..color = overlayColor,
   157→    );
   158→  }
   159→
   160→  @override
   161→  bool shouldRepaint(_SpotlightPainter oldDelegate) =>
   162→      oldDelegate.targetRect != targetRect ||
   163→      oldDelegate.overlayColor != overlayColor ||
   164→      oldDelegate.borderRadius != borderRadius;
   165→}
