     3→import 'package:flutter/services.dart';
     4→import 'package:flutter/widgets.dart';
     5→
     6→// ── Shortcut activator ──────────────────────────────────────────────────────
     7→
     8→/// Platform-aware keyboard shortcut activator.
     9→///
    10→/// Automatically maps [LogicalKeyboardKey] modifiers:
    11→/// - `Ctrl` maps to `Cmd` on macOS/iOS
    12→/// - `Ctrl` stays `Ctrl` on Windows/Linux/Web
    13→///
    14→/// {@category Composites}
    15→class OiShortcutActivator extends SingleActivator {
    16→  /// Creates an [OiShortcutActivator] with explicit modifier flags.
    17→  ///
    18→  /// Prefer [OiShortcutActivator.primary] for platform-adaptive shortcuts.
    19→  const OiShortcutActivator(
    20→    super.trigger, {
    21→    super.control,
    22→    super.shift,
    23→    super.alt,
    24→    super.meta,
    25→  });
    26→
    27→  /// Creates a shortcut using the primary modifier (Ctrl/Cmd).
    28→  ///
    29→  /// On macOS and iOS the primary modifier is `Cmd` (meta); on all other
    30→  /// platforms it is `Ctrl` (control).
    31→  factory OiShortcutActivator.primary(
    32→    LogicalKeyboardKey key, {
    33→    bool shift = false,
    34→    bool alt = false,
    35→  }) {
    36→    final useMeta = _isApplePlatform;
    37→    return OiShortcutActivator(
    38→      key,
    39→      control: !useMeta,
    40→      meta: useMeta,
    41→      shift: shift,
    42→      alt: alt,
    43→    );
    44→  }
    45→
    46→  /// Whether the current platform uses Cmd instead of Ctrl.
    47→  static bool get _isApplePlatform {
