import 'package:flutter/foundation.dart'
    show defaultTargetPlatform, kIsWeb;
import 'package:flutter/services.dart';
import 'package:flutter/widgets.dart';

// ── Shortcut activator ──────────────────────────────────────────────────────

/// Platform-aware keyboard shortcut activator.
///
/// Automatically maps [LogicalKeyboardKey] modifiers:
/// - `Ctrl` maps to `Cmd` on macOS/iOS
/// - `Ctrl` stays `Ctrl` on Windows/Linux/Web
///
/// {@category Composites}
class OiShortcutActivator extends SingleActivator {
  /// Creates an [OiShortcutActivator] with explicit modifier flags.
  ///
  /// Prefer [OiShortcutActivator.primary] for platform-adaptive shortcuts.
  const OiShortcutActivator(
    super.trigger, {
    super.control,
    super.shift,
    super.alt,
    super.meta,
  });

  /// Creates a shortcut using the primary modifier (Ctrl/Cmd).
  ///
  /// On macOS and iOS the primary modifier is `Cmd` (meta); on all other
  /// platforms it is `Ctrl` (control).
  factory OiShortcutActivator.primary(
    LogicalKeyboardKey key, {
    bool shift = false,
    bool alt = false,
  }) {
    final useMeta = _isApplePlatform;
    return OiShortcutActivator(
      key,
      control: !useMeta,
      meta: useMeta,
      shift: shift,
      alt: alt,
    );
  }

  /// Whether the current platform uses Cmd instead of Ctrl.
  static bool get _isApplePlatform {
    if (kIsWeb) return false;
    return defaultTargetPlatform == TargetPlatform.macOS ||
        defaultTargetPlatform == TargetPlatform.iOS;
  }

  /// Human-readable display label for this shortcut.
  ///
  /// Returns a platform-appropriate string such as `"Cmd+Z"` on macOS or
  /// `"Ctrl+Z"` on other platforms.
  String get displayLabel {
    final parts = <String>[];

    if (control) {
      parts.add(_isApplePlatform ? 'Ctrl' : 'Ctrl');
    }
    if (meta) {
      parts.add(_isApplePlatform ? 'Cmd' : 'Meta');
    }
    if (alt) {
      parts.add(_isApplePlatform ? 'Opt' : 'Alt');
    }
    if (shift) {
      parts.add('Shift');
    }

    parts.add(_keyLabel(trigger));

    return parts.join('+');
  }

  /// Returns a short human-readable label for a [LogicalKeyboardKey].
  static String _keyLabel(LogicalKeyboardKey key) {
    // Map well-known keys to concise labels.
    if (key == LogicalKeyboardKey.delete) return 'Del';
    if (key == LogicalKeyboardKey.backspace) return 'Backspace';
    if (key == LogicalKeyboardKey.enter) return 'Enter';
    if (key == LogicalKeyboardKey.escape) return 'Esc';
    if (key == LogicalKeyboardKey.tab) return 'Tab';
    if (key == LogicalKeyboardKey.space) return 'Space';
    if (key == LogicalKeyboardKey.arrowUp) return 'Up';
    if (key == LogicalKeyboardKey.arrowDown) return 'Down';
    if (key == LogicalKeyboardKey.arrowLeft) return 'Left';
    if (key == LogicalKeyboardKey.arrowRight) return 'Right';

    // Fall back to the key label, uppercased for single characters.
    final label = key.keyLabel;
    if (label.length == 1) return label.toUpperCase();
    return label;
  }
}

// ── Shortcut binding ────────────────────────────────────────────────────────

/// A binding between a keyboard shortcut and an action.
///
/// Combines a [ShortcutActivator] with a human-readable [label] and an
/// [onInvoke] callback. An optional [category] groups related shortcuts
/// in the help overlay.
///
/// {@category Composites}
class OiShortcutBinding {
  /// Creates an [OiShortcutBinding].
  const OiShortcutBinding({
    required this.activator,
    required this.label,
    required this.onInvoke,
    this.description,
    this.category,
  });

  /// The keyboard activator that triggers this shortcut.
  final ShortcutActivator activator;

  /// A short human-readable label displayed in the help overlay.
  final String label;

  /// An optional longer description for the help overlay.
  final String? description;

  /// An optional category used to group shortcuts in the help overlay.
  final String? category;

  /// The callback invoked when the shortcut is triggered.
  final VoidCallback onInvoke;
}

// ── Intent / Action glue ────────────────────────────────────────────────────

/// An [Intent] that carries the index of the binding to invoke.
class _OiShortcutIntent extends Intent {
  /// Creates an [_OiShortcutIntent] with the given [index].
  const _OiShortcutIntent(this.index);

  /// The index into the [OiShortcuts.shortcuts] list.
  final int index;
}

/// An [Action] that looks up the binding by index and calls [onInvoke].
class _OiShortcutAction extends Action<_OiShortcutIntent> {
  /// Creates an [_OiShortcutAction] with the given [bindings].
  _OiShortcutAction(this.bindings);

  /// The list of shortcut bindings to dispatch against.
  final List<OiShortcutBinding> bindings;

  @override
  Object? invoke(_OiShortcutIntent intent) {
    bindings[intent.index].onInvoke();
    return null;
  }
}

/// An [Intent] that opens the shortcut help overlay.
class _OiShowHelpIntent extends Intent {
  /// Creates an [_OiShowHelpIntent].
  const _OiShowHelpIntent();
}

/// An [Action] that builds and shows the help overlay.
class _OiShowHelpAction extends Action<_OiShowHelpIntent> {
  /// Creates an [_OiShowHelpAction] with the given [bindings].
  _OiShowHelpAction(this.bindings);

  /// The list of shortcut bindings to display.
  final List<OiShortcutBinding> bindings;

  @override
  Object? invoke(_OiShowHelpIntent intent) {
    // The help overlay is shown by the OiShortcuts widget itself via
    // OverlayEntry. This action just triggers the callback.
    _onShowHelp?.call();
    return null;
  }

  /// External callback wired by [_OiShortcutsState].
  VoidCallback? _onShowHelp;
}

// ── OiShortcuts widget ──────────────────────────────────────────────────────

/// Keyboard shortcut manager with optional help overlay.
///
/// Registers shortcuts globally or per-scope, and shows a "?" help
/// dialog listing all active shortcuts when [showHelpOnQuestionMark] is
/// `true`.
///
/// {@category Composites}
class OiShortcuts extends StatefulWidget {
  /// Creates an [OiShortcuts].
  const OiShortcuts({
    required this.child,
    required this.shortcuts,
    this.showHelpOnQuestionMark = true,
    super.key,
  });

  /// The widget subtree to which shortcuts apply.
  final Widget child;

  /// The list of keyboard shortcut bindings.
  final List<OiShortcutBinding> shortcuts;

  /// Whether pressing `?` (Shift + Slash) opens the help overlay.
  ///
  /// Defaults to `true`.
  final bool showHelpOnQuestionMark;

  @override
  State<OiShortcuts> createState() => _OiShortcutsState();
}

class _OiShortcutsState extends State<OiShortcuts> {
  /// Tracks whether the help overlay is currently visible.
  OverlayEntry? _helpOverlay;

  @override
  void dispose() {
    _removeHelpOverlay();
    super.dispose();
  }

  // ── Help overlay ────────────────────────────────────────────────────────

  /// Shows the help overlay listing all registered shortcuts.
  void _showHelpOverlay() {
    if (_helpOverlay != null) return;

    final entry = OverlayEntry(
      builder: (context) => _OiShortcutHelpOverlay(
        bindings: widget.shortcuts,
        onDismiss: _removeHelpOverlay,
      ),
    );

    Overlay.of(context).insert(entry);
    _helpOverlay = entry;
  }

  /// Removes the help overlay if visible.
  void _removeHelpOverlay() {
    _helpOverlay?.remove();
    _helpOverlay = null;
  }

  // ── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    // Build the shortcut → intent map.
    final shortcutMap = <ShortcutActivator, Intent>{};
    for (var i = 0; i < widget.shortcuts.length; i++) {
      shortcutMap[widget.shortcuts[i].activator] = _OiShortcutIntent(i);
    }

    // Wire up the help action callback.
    final helpAction = _OiShowHelpAction(widget.shortcuts)
      .._onShowHelp = _showHelpOverlay;

    // Add "?" shortcut for help if enabled.
    if (widget.showHelpOnQuestionMark) {
      shortcutMap[const SingleActivator(
        LogicalKeyboardKey.slash,
        shift: true,
      )] = const _OiShowHelpIntent();
    }

    return Shortcuts(
      shortcuts: shortcutMap,
      child: Actions(
        actions: <Type, Action<Intent>>{
          _OiShortcutIntent: _OiShortcutAction(widget.shortcuts),
          if (widget.showHelpOnQuestionMark) _OiShowHelpIntent: helpAction,
        },
        child: Focus(
          autofocus: true,
          child: widget.child,
        ),
      ),
    );
  }
}

// ── Help overlay ────────────────────────────────────────────────────────────

/// A full-screen overlay that lists all registered shortcuts grouped by
/// category.
class _OiShortcutHelpOverlay extends StatelessWidget {
  /// Creates an [_OiShortcutHelpOverlay].
  const _OiShortcutHelpOverlay({
    required this.bindings,
    required this.onDismiss,
  });

  /// The shortcut bindings to display.
  final List<OiShortcutBinding> bindings;

  /// Called when the overlay should be dismissed.
  final VoidCallback onDismiss;

  @override
  Widget build(BuildContext context) {
    // Group bindings by category.
    final grouped = <String, List<OiShortcutBinding>>{};
    for (final binding in bindings) {
      final cat = binding.category ?? 'General';
      grouped.putIfAbsent(cat, () => []).add(binding);
    }

    final children = <Widget>[];
    for (final entry in grouped.entries) {
      children.add(
        Padding(
          padding: const EdgeInsets.only(bottom: 8),
          child: Text(
            entry.key,
            style: const TextStyle(
              fontWeight: FontWeight.bold,
              fontSize: 16,
            ),
          ),
        ),
      );
      for (final binding in entry.value) {
        final activatorLabel = binding.activator is OiShortcutActivator
            ? (binding.activator as OiShortcutActivator).displayLabel
            : binding.activator.toString();
        children.add(
          Padding(
            padding: const EdgeInsets.only(bottom: 4),
            child: Row(
              children: [
                SizedBox(
                  width: 120,
                  child: Text(activatorLabel),
                ),
                Expanded(child: Text(binding.label)),
              ],
            ),
          ),
        );
      }
      children.add(const SizedBox(height: 12));
    }

    return GestureDetector(
      onTap: onDismiss,
      behavior: HitTestBehavior.opaque,
      child: ColoredBox(
        color: const Color(0x88000000),
        child: Center(
          child: GestureDetector(
            onTap: () {}, // Absorb taps on the dialog body.
            child: Container(
              constraints: const BoxConstraints(maxWidth: 400, maxHeight: 500),
              padding: const EdgeInsets.all(24),
              decoration: BoxDecoration(
                color: const Color(0xFFFFFFFF),
                borderRadius: BorderRadius.circular(8),
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Text(
                    'Keyboard Shortcuts',
                    style: TextStyle(
                      fontWeight: FontWeight.bold,
                      fontSize: 20,
                    ),
                  ),
                  const SizedBox(height: 16),
                  Flexible(
                    child: SingleChildScrollView(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: children,
                      ),
                    ),
                  ),
                  const SizedBox(height: 16),
                  Align(
                    alignment: Alignment.centerRight,
                    child: GestureDetector(
                      onTap: onDismiss,
                      child: const Text('Close'),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }
}

import 'package:flutter/widgets.dart';
import 'package:obers_ui/src/foundation/theme/oi_theme.dart';
import 'package:obers_ui/src/primitives/display/oi_image.dart';

// ── Selection mode ────────────────────────────────────────────────────────────

/// Selection behaviour for list / grid widgets.
///
/// {@category Composites}
enum OiSelectionMode {
  /// No selection is allowed.
  none,

  /// Only a single item can be selected at a time.
  single,

  /// Multiple items can be selected simultaneously.
  multi,
}

// ── Gallery item ──────────────────────────────────────────────────────────────

/// An item in the gallery.
///
/// {@category Composites}
class OiGalleryItem {
  /// Creates an [OiGalleryItem].
  const OiGalleryItem({
    required this.key,
    required this.src,
    required this.alt,
    this.thumbnailUrl,
  });

  /// Unique identifier for this gallery item.
  final Object key;

  /// The image source URL or asset path.
  final String src;

  /// Accessibility description for the image.
  final String alt;

  /// An optional smaller thumbnail URL used in the grid.
  final String? thumbnailUrl;
}

// ── Gallery widget ────────────────────────────────────────────────────────────

/// Image / media gallery grid with selection and lightbox preview.
///
/// Displays [items] in a grid with [columns] columns. Items can be tapped
/// individually via [onItemTap]. When [selectionMode] is not
/// [OiSelectionMode.none], tapping toggles selection and [onSelectionChange]
/// reports the updated [selectedKeys].
///
/// {@category Composites}
class OiGallery extends StatelessWidget {
  /// Creates an [OiGallery].
  const OiGallery({
    required this.items,
    required this.label,
    this.columns = 4,
    super.key,
    this.selectionMode = OiSelectionMode.none,
    this.selectedKeys = const {},
    this.onSelectionChange,
    this.onItemTap,
    this.showUpload = false,
    this.onUpload,
    this.gap = 8,
  });

  /// The list of gallery items.
  final List<OiGalleryItem> items;

  /// Semantic label for the gallery.
  final String label;

  /// Number of columns in the grid.
  final int columns;

  /// The selection behaviour.
  final OiSelectionMode selectionMode;

  /// The set of currently selected item keys.
  final Set<Object> selectedKeys;

  /// Called when the selection changes.
  final ValueChanged<Set<Object>>? onSelectionChange;

  /// Called when an item is tapped (regardless of selection mode).
  final ValueChanged<OiGalleryItem>? onItemTap;

  /// Whether an upload placeholder tile is shown at the end.
  final bool showUpload;

  /// Called when the upload tile is tapped. The list parameter can carry
  /// platform-specific file references.
  final ValueChanged<List<Object>>? onUpload;

  /// The gap in logical pixels between grid cells.
  final double gap;

  void _handleTap(OiGalleryItem item) {
    onItemTap?.call(item);

    if (selectionMode == OiSelectionMode.none) return;

    final newSelection = Set<Object>.from(selectedKeys);
    if (selectionMode == OiSelectionMode.single) {
      if (newSelection.contains(item.key)) {
        newSelection.remove(item.key);
      } else {
        newSelection
          ..clear()
          ..add(item.key);
      }
    } else {
      // multi
      if (newSelection.contains(item.key)) {
        newSelection.remove(item.key);
      } else {
        newSelection.add(item.key);
      }
    }
    onSelectionChange?.call(newSelection);
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.colors;
    final textTheme = context.textTheme;

    if (items.isEmpty && !showUpload) {
      return Semantics(
        container: true,
        label: label,
        child: const SizedBox.shrink(key: Key('oi_gallery_empty')),
      );
    }

    final totalCount = items.length + (showUpload ? 1 : 0);

    return Semantics(
      container: true,
      explicitChildNodes: true,
      label: label,
      child: GridView.builder(
        key: const Key('oi_gallery'),
        shrinkWrap: true,
        itemCount: totalCount,
        gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
          crossAxisCount: columns,
          mainAxisSpacing: gap,
          crossAxisSpacing: gap,
        ),
        itemBuilder: (context, index) {
          // Upload tile
          if (showUpload && index == items.length) {
            return GestureDetector(
              key: const Key('oi_gallery_upload'),
              onTap: () => onUpload?.call(const []),
              child: Semantics(
                label: 'Upload media',
                button: true,
                child: Container(
                  decoration: BoxDecoration(
                    color: colors.surfaceHover,
                    borderRadius: BorderRadius.circular(8),
                    border: Border.all(
                      color: colors.border,
                    ),
                  ),
                  child: Center(
                    child: Text(
                      '+',
                      style: textTheme.h2.copyWith(
                        color: colors.textMuted,
                      ),
                    ),
                  ),
                ),
              ),
            );
          }

          final item = items[index];
          final isSelected = selectedKeys.contains(item.key);
          final imgSrc = item.thumbnailUrl ?? item.src;

          return GestureDetector(
            onTap: () => _handleTap(item),
            child: Semantics(
              label: item.alt,
              selected: isSelected,
              child: Container(
                key: ValueKey('oi_gallery_item_${item.key}'),
                decoration: BoxDecoration(
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(
                    color: isSelected
                        ? colors.primary.base
                        : colors.borderSubtle,
                    width: isSelected ? 2 : 1,
                  ),
                ),
                child: ClipRRect(
                  borderRadius: BorderRadius.circular(7),
                  child: Stack(
                    fit: StackFit.expand,
                    children: [
                      OiImage.decorative(
                        src: imgSrc,
                        fit: BoxFit.cover,
                      ),
                      if (isSelected)
                        Positioned(
                          top: 4,
                          right: 4,
                          child: Container(
                            width: 24,
                            height: 24,
                            decoration: BoxDecoration(
                              color: colors.primary.base,
                              shape: BoxShape.circle,
                            ),
                            child: Center(
                              child: Text(
                                '\u2713',
                                style: TextStyle(
                                  color: colors.textOnPrimary,
                                  fontSize: 14,
                                  height: 1,
                                ),
                              ),
                            ),
                          ),
                        ),
                    ],
                  ),
                ),
              ),
            ),
          );
        },
      ),
    );
  }
}

import 'package:flutter/services.dart';
import 'package:flutter/widgets.dart';
import 'package:obers_ui/src/foundation/theme/oi_theme.dart';
import 'package:obers_ui/src/primitives/display/oi_image.dart';

/// An item in the lightbox gallery.
///
/// {@category Composites}
class OiLightboxItem {
  /// Creates an [OiLightboxItem].
  const OiLightboxItem({
    required this.src,
    required this.alt,
    this.caption,
  });

  /// The image source URL or asset path.
  final String src;

  /// Accessibility description for the image.
  final String alt;

  /// Optional caption displayed below the image.
  final String? caption;
}

/// Full-screen image viewer with gallery navigation, zoom, and thumbnails.
///
/// Displays images in a full-screen overlay with swipe navigation,
/// pinch-to-zoom, thumbnail strip, and captions.
///
/// {@category Composites}
class OiLightbox extends StatefulWidget {
  /// Creates an [OiLightbox].
  const OiLightbox({
    required this.items,
    required this.initialIndex,
    required this.label,
    this.onDismiss,
    this.showThumbnails = true,
    this.enableZoom = true,
    this.enableSwipe = true,
    super.key,
  });

  /// The list of images to display in the lightbox.
  final List<OiLightboxItem> items;

  /// The index of the initially displayed image.
  final int initialIndex;

  /// Called when the lightbox is dismissed (close button or background tap).
  final VoidCallback? onDismiss;

  /// Whether to show the thumbnail strip at the bottom.
  final bool showThumbnails;

  /// Whether pinch-to-zoom is enabled on the displayed image.
  final bool enableZoom;

  /// Whether horizontal swipe navigation between images is enabled.
  final bool enableSwipe;

  /// Semantic label for the lightbox widget.
  final String label;

  @override
  State<OiLightbox> createState() => _OiLightboxState();
}

class _OiLightboxState extends State<OiLightbox> {
  late int _currentIndex;
  late final FocusNode _focusNode;

  @override
  void initState() {
    super.initState();
    _currentIndex = widget.initialIndex.clamp(0, _maxIndex);
    _focusNode = FocusNode();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) _focusNode.requestFocus();
    });
  }

  @override
  void dispose() {
    _focusNode.dispose();
    super.dispose();
  }

  int get _maxIndex =>
      widget.items.isEmpty ? 0 : widget.items.length - 1;

  /// Whether navigation to the previous image is possible.
  bool get _hasPrevious => _currentIndex > 0;

  /// Whether navigation to the next image is possible.
  bool get _hasNext => _currentIndex < _maxIndex;

  void _goTo(int index) {
    if (index < 0 || index > _maxIndex) return;
    setState(() => _currentIndex = index);
  }

  void _previous() {
    if (_hasPrevious) _goTo(_currentIndex - 1);
  }

  void _next() {
    if (_hasNext) _goTo(_currentIndex + 1);
  }

  KeyEventResult _handleKey(FocusNode node, KeyEvent event) {
    if (event is! KeyDownEvent) return KeyEventResult.ignored;
    if (event.logicalKey == LogicalKeyboardKey.arrowLeft) {
      _previous();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.arrowRight) {
      _next();
      return KeyEventResult.handled;
    }
    if (event.logicalKey == LogicalKeyboardKey.escape) {
      widget.onDismiss?.call();
      return KeyEventResult.handled;
    }
    return KeyEventResult.ignored;
  }

  @override
  Widget build(BuildContext context) {
    if (widget.items.isEmpty) return const SizedBox.shrink();

    final colors = context.colors;
    final textTheme = context.textTheme;
    final item = widget.items[_currentIndex];

    Widget image = OiImage(
      key: ValueKey('oi_lightbox_image_$_currentIndex'),
      src: item.src,
      alt: item.alt,
      fit: BoxFit.contain,
    );

    if (widget.enableZoom) {
      image = InteractiveViewer(
        key: const Key('oi_lightbox_zoom'),
        minScale: 0.5,
        maxScale: 4,
        child: image,
      );
    }

    if (widget.enableSwipe) {
      image = GestureDetector(
        key: const Key('oi_lightbox_swipe'),
        onHorizontalDragEnd: (details) {
          final velocity = details.primaryVelocity ?? 0;
          if (velocity > 200) {
            _previous();
          } else if (velocity < -200) {
            _next();
          }
        },
        child: image,
      );
    }

    return Focus(
      focusNode: _focusNode,
      onKeyEvent: _handleKey,
      child: Semantics(
        container: true,
        explicitChildNodes: true,
        label: widget.label,
        child: Stack(
          key: const Key('oi_lightbox'),
          children: [
            // Scrim
            Positioned.fill(
              child: GestureDetector(
                behavior: HitTestBehavior.opaque,
                onTap: widget.onDismiss,
                child: ColoredBox(color: colors.overlay),
              ),
            ),

            // Main image area
            Positioned.fill(
              child: Padding(
                padding: const EdgeInsets.symmetric(
                  horizontal: 56,
                  vertical: 72,
                ),
                child: image,
              ),
            ),

            // Close button
            Positioned(
              top: 16,
              right: 16,
              child: GestureDetector(
                key: const Key('oi_lightbox_close'),
                onTap: widget.onDismiss,
                child: Semantics(
                  label: 'Close lightbox',
                  button: true,
                  child: Container(
                    width: 40,
                    height: 40,
                    decoration: BoxDecoration(
                      color: colors.surface.withValues(alpha: 0.8),
                      shape: BoxShape.circle,
                    ),
                    child: Center(
                      child: Text(
                        '\u00D7',
                        style: TextStyle(
                          fontSize: 24,
                          color: colors.text,
                          height: 1,
                        ),
                      ),
                    ),
                  ),
                ),
              ),
            ),

            // Previous arrow
            if (_hasPrevious)
              Positioned(
                left: 8,
                top: 0,
                bottom: 0,
                child: Center(
                  child: GestureDetector(
                    key: const Key('oi_lightbox_previous'),
                    onTap: _previous,
                    child: Semantics(
                      label: 'Previous image',
                      button: true,
                      child: Container(
                        width: 40,
                        height: 40,
                        decoration: BoxDecoration(
                          color: colors.surface.withValues(alpha: 0.8),
                          shape: BoxShape.circle,
                        ),
                        child: Center(
                          child: Text(
                            '\u2039',
                            style: TextStyle(
                              fontSize: 24,
                              color: colors.text,
                              height: 1,
                            ),
                          ),
                        ),
                      ),
                    ),
                  ),
                ),
              ),

            // Next arrow
            if (_hasNext)
              Positioned(
                right: 8,
                top: 0,
                bottom: 0,
                child: Center(
                  child: GestureDetector(
                    key: const Key('oi_lightbox_next'),
                    onTap: _next,
                    child: Semantics(
                      label: 'Next image',
                      button: true,
                      child: Container(
                        width: 40,
                        height: 40,
                        decoration: BoxDecoration(
                          color: colors.surface.withValues(alpha: 0.8),
                          shape: BoxShape.circle,
                        ),
                        child: Center(
                          child: Text(
                            '\u203A',
                            style: TextStyle(
                              fontSize: 24,
                              color: colors.text,
                              height: 1,
                            ),
                          ),
                        ),
                      ),
                    ),
                  ),
                ),
              ),

            // Caption
            if (item.caption != null)
              Positioned(
                left: 56,
                right: 56,
                bottom: widget.showThumbnails ? 88 : 16,
                child: Center(
                  child: Text(
                    item.caption!,
                    key: const Key('oi_lightbox_caption'),
                    style: textTheme.body.copyWith(
                      color: colors.textInverse,
                    ),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),

            // Thumbnail strip
            if (widget.showThumbnails && widget.items.length > 1)
              Positioned(
                left: 0,
                right: 0,
                bottom: 16,
                child: SizedBox(
                  height: 56,
                  child: Center(
                    child: ListView.separated(
                      key: const Key('oi_lightbox_thumbnails'),
                      scrollDirection: Axis.horizontal,
                      shrinkWrap: true,
                      itemCount: widget.items.length,
                      separatorBuilder: (_, __) => const SizedBox(width: 8),
                      itemBuilder: (context, index) {
                        final thumbItem = widget.items[index];
                        final isSelected = index == _currentIndex;
                        return GestureDetector(
                          onTap: () => _goTo(index),
                          child: Semantics(
                            label: thumbItem.alt,
                            selected: isSelected,
                            child: Container(
                              width: 56,
                              height: 56,
                              decoration: BoxDecoration(
                                border: Border.all(
                                  color: isSelected
                                      ? colors.primary.base
                                      : colors.border,
                                  width: isSelected ? 2 : 1,
                                ),
                                borderRadius: BorderRadius.circular(4),
                              ),
                              child: ClipRRect(
                                borderRadius: BorderRadius.circular(3),
                                child: OiImage.decorative(
                                  src: thumbItem.src,
                                  width: 56,
                                  height: 56,
                                  fit: BoxFit.cover,
                                ),
                              ),
                            ),
                          ),
                        );
                      },
                    ),
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }
}

import 'dart:math' as math;

import 'package:flutter/widgets.dart';
import 'package:obers_ui/src/foundation/theme/oi_theme.dart';

/// A segment of the gauge for coloring ranges.
///
/// Each segment covers a value range from [from] to [to] and is painted
/// with the given [color]. An optional [label] can describe the segment.
class OiGaugeSegment {
  /// Creates an [OiGaugeSegment].
  const OiGaugeSegment({
    required this.from,
    required this.to,
    required this.color,
    this.label,
  });

  /// The start value of this segment range.
  final double from;

  /// The end value of this segment range.
  final double to;

  /// The color used to paint this segment arc.
  final Color color;

  /// An optional human-readable label for this segment.
  final String? label;
}

/// A gauge / speedometer visualization showing a value within a range.
///
/// The gauge renders a 240-degree arc from [min] to [max] with an optional
/// needle indicator at [value]. Colored [segments] can highlight ranges,
/// and a [target] marker can indicate a goal value.
///
/// When [showValue] is `true`, the current value is displayed below the arc.
/// The [formatValue] callback can be used to customize the value string.
///
/// {@category Composites}
class OiGauge extends StatelessWidget {
  /// Creates an [OiGauge].
  const OiGauge({
    required this.value,
    required this.label,
    super.key,
    this.min = 0,
    this.max = 100,
    this.segments,
    this.formatValue,
    this.showValue = true,
    this.target,
    this.size,
  });

  /// The current value displayed by the needle.
  final double value;

  /// The accessibility label for the gauge.
  final String label;

  /// The minimum value of the gauge range.
  final double min;

  /// The maximum value of the gauge range.
  final double max;

  /// Optional colored segments defining value ranges on the arc.
  final List<OiGaugeSegment>? segments;

  /// An optional callback to format the displayed value string.
  final String Function(double)? formatValue;

  /// Whether to display the numeric value below the gauge.
  final bool showValue;

  /// An optional target/goal value shown as a marker on the arc.
  final double? target;

  /// The diameter of the gauge. Defaults to the available width.
  final double? size;

  @override
  Widget build(BuildContext context) {
    final colors = context.colors;
    final effectiveSize = size ?? 200;

    return Semantics(
      label: label,
      value: _formattedValue,
      child: SizedBox(
        width: effectiveSize,
        height: effectiveSize * 0.7,
        child: CustomPaint(
          key: const Key('oi_gauge_painter'),
          size: Size(effectiveSize, effectiveSize * 0.7),
          painter: _OiGaugePainter(
            value: value.clamp(min, max),
            min: min,
            max: max,
            segments: segments,
            target: target,
            trackColor: colors.borderSubtle,
            needleColor: colors.text,
            targetColor: colors.warning.base,
            defaultSegmentColor: colors.primary.base,
          ),
          child: showValue
              ? Align(
                  alignment: Alignment.bottomCenter,
                  child: Padding(
                    padding: const EdgeInsets.only(bottom: 4),
                    child: Text(
                      _formattedValue,
                      key: const Key('oi_gauge_value'),
                      style: TextStyle(
                        color: colors.text,
                        fontSize: effectiveSize * 0.1,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  ),
                )
              : null,
        ),
      ),
    );
  }

  String get _formattedValue =>
      formatValue?.call(value) ?? value.toStringAsFixed(0);
}

/// Custom painter for the gauge arc, segments, needle, and target marker.
class _OiGaugePainter extends CustomPainter {
  _OiGaugePainter({
    required this.value,
    required this.min,
    required this.max,
    required this.segments,
    required this.target,
    required this.trackColor,
    required this.needleColor,
    required this.targetColor,
    required this.defaultSegmentColor,
  });

  /// The current gauge value.
  final double value;

  /// The minimum gauge value.
  final double min;

  /// The maximum gauge value.
  final double max;

  /// Optional colored segments.
  final List<OiGaugeSegment>? segments;

  /// Optional target marker value.
  final double? target;

  /// The color of the background track arc.
  final Color trackColor;

  /// The color of the needle.
  final Color needleColor;

  /// The color of the target marker.
  final Color targetColor;

  /// The default segment color when none is provided.
  final Color defaultSegmentColor;

  static const double _startAngle = math.pi * 0.75; // 135 degrees
  static const double _sweepAngle = math.pi * 1.5; // 270 degrees

  @override
  void paint(Canvas canvas, Size size) {
    final center = Offset(size.width / 2, size.height * 0.85);
    final radius = math.min(size.width, size.height * 1.4) / 2 * 0.8;
    final strokeWidth = radius * 0.15;

    // Draw track arc.
    final trackPaint = Paint()
      ..color = trackColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = strokeWidth
      ..strokeCap = StrokeCap.round;

    canvas.drawArc(
      Rect.fromCircle(center: center, radius: radius),
      _startAngle,
      _sweepAngle,
      false,
      trackPaint,
    );

    // Draw segments.
    if (segments != null) {
      for (final segment in segments!) {
        final segStart = _valueToAngle(segment.from.clamp(min, max));
        final segEnd = _valueToAngle(segment.to.clamp(min, max));
        final segPaint = Paint()
          ..color = segment.color
          ..style = PaintingStyle.stroke
          ..strokeWidth = strokeWidth
          ..strokeCap = StrokeCap.butt;

        canvas.drawArc(
          Rect.fromCircle(center: center, radius: radius),
          segStart,
          segEnd - segStart,
          false,
          segPaint,
        );
      }
    }

    // Draw target marker.
    if (target != null) {
      final targetAngle = _valueToAngle(target!.clamp(min, max));
      final markerPaint = Paint()
        ..color = targetColor
        ..style = PaintingStyle.stroke
        ..strokeWidth = 3;

      final innerR = radius - strokeWidth;
      final outerR = radius + strokeWidth;
      final innerPoint = Offset(
        center.dx + innerR * math.cos(targetAngle),
        center.dy + innerR * math.sin(targetAngle),
      );
      final outerPoint = Offset(
        center.dx + outerR * math.cos(targetAngle),
        center.dy + outerR * math.sin(targetAngle),
      );
      canvas.drawLine(innerPoint, outerPoint, markerPaint);
    }

    // Draw needle.
    final needleAngle = _valueToAngle(value);
    final needleLength = radius * 0.85;
    final needleTip = Offset(
      center.dx + needleLength * math.cos(needleAngle),
      center.dy + needleLength * math.sin(needleAngle),
    );

    final needlePaint = Paint()
      ..color = needleColor
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2.5
      ..strokeCap = StrokeCap.round;

    canvas.drawLine(center, needleTip, needlePaint);

    // Draw center dot.
    final dotPaint = Paint()..color = needleColor;
    canvas.drawCircle(center, 4, dotPaint);
  }

  double _valueToAngle(double v) {
    final ratio = (v - min) / (max - min);
    return _startAngle + ratio * _sweepAngle;
  }

  @override
  bool shouldRepaint(_OiGaugePainter oldDelegate) =>
      oldDelegate.value != value ||
      oldDelegate.min != min ||
      oldDelegate.max != max ||
      oldDelegate.target != target ||
      oldDelegate.segments != segments ||
      oldDelegate.trackColor != trackColor ||
      oldDelegate.needleColor != needleColor;
}

import 'package:flutter/services.dart';
import 'package:flutter/widgets.dart';
import 'package:obers_ui/src/components/display/oi_badge.dart';
import 'package:obers_ui/src/components/display/oi_tooltip.dart';
import 'package:obers_ui/src/foundation/theme/oi_theme.dart';
import 'package:obers_ui/src/primitives/interaction/oi_tappable.dart';

// ── Data models ──────────────────────────────────────────────────────────────

/// A section within the sidebar.
///
/// Sections group related [items] under an optional [title]. When
/// [collapsible] is `true` the section can be expanded and collapsed by
/// tapping its header.
@immutable
class OiSidebarSection {
  /// Creates an [OiSidebarSection].
  const OiSidebarSection({
    required this.items,
    this.title,
    this.collapsible = true,
  });

  /// The optional header title for this section.
  ///
  /// When `null` no header is rendered and the items appear without a
  /// visual grouping label.
  final String? title;

  /// The navigation items displayed in this section.
  final List<OiSidebarItem> items;

  /// Whether the section can be collapsed by the user.
  ///
  /// When `true` (the default) a tap on the section header toggles
  /// visibility of its [items].
  final bool collapsible;
}

/// An item in the sidebar.
///
/// Each item has a unique [id], a display [label], and an [icon]. Items may
/// optionally carry a [badgeCount], nested [children], or be [disabled].
@immutable
class OiSidebarItem {
  /// Creates an [OiSidebarItem].
  const OiSidebarItem({
    required this.id,
    required this.label,
    required this.icon,
    this.badgeCount,
    this.children,
    this.disabled = false,
  });

  /// A unique identifier used to track selection.
  final String id;

  /// The display label shown next to the icon in full mode.
  final String label;

  /// The icon displayed for this item.
  final IconData icon;

  /// An optional badge count displayed to the right of the label.
  ///
  /// When `null` no badge is shown.
  final int? badgeCount;

  /// Optional nested child items.
  ///
  /// When non-null the item acts as a parent that can be expanded to reveal
  /// its children.
  final List<OiSidebarItem>? children;

  /// Whether this item is non-interactive.
  final bool disabled;
}

