import 'package:flutter/widgets.dart';

/// Highlights a single widget by dimming everything else.
///
/// Renders an overlay with a transparent cutout around the [target] widget.
/// Used for single-step highlighting and as a building block for [OiTour].
///
/// {@category Composites}
class OiSpotlight extends StatefulWidget {
  /// Creates an [OiSpotlight].
  const OiSpotlight({
    required this.target,
    required this.child,
    this.active = true,
    this.overlayColor,
    this.padding = 8,
    this.borderRadius,
    this.onTapOutside,
    super.key,
  });

  /// The [GlobalKey] of the widget to spotlight.
  final GlobalKey target;

  /// The child widget tree (the full page content).
  final Widget child;

  /// Whether the spotlight overlay is active.
  ///
  /// When `false`, only [child] is rendered with no overlay.
  final bool active;

  /// The color of the dimmed overlay.
  ///
  /// Defaults to black54.
  final Color? overlayColor;

  /// Padding in logical pixels around the spotlighted widget.
  final double padding;

  /// Border radius of the cutout.
  ///
  /// When `null`, the cutout is a plain rectangle.
  final BorderRadius? borderRadius;

  /// Called when the user taps outside the spotlighted area.
  final VoidCallback? onTapOutside;

  @override
  State<OiSpotlight> createState() => _OiSpotlightState();
}

class _OiSpotlightState extends State<OiSpotlight> {
  Rect? _targetRect;

  @override
  void initState() {
    super.initState();
    if (widget.active) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _updateTargetRect();
      });
    }
  }

  @override
  void didUpdateWidget(OiSpotlight oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (widget.active &&
        (!oldWidget.active || widget.target != oldWidget.target)) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _updateTargetRect();
      });
    }
  }

  void _updateTargetRect() {
    final renderObject = widget.target.currentContext?.findRenderObject();
    if (renderObject is RenderBox && renderObject.hasSize) {
      final offset = renderObject.localToGlobal(Offset.zero);
      final size = renderObject.size;
      if (mounted) {
        setState(() {
          _targetRect = Rect.fromLTWH(
            offset.dx - widget.padding,
            offset.dy - widget.padding,
            size.width + widget.padding * 2,
            size.height + widget.padding * 2,
          );
        });
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    if (!widget.active) {
      return widget.child;
    }

    return Stack(
      children: [
        widget.child,
        if (_targetRect != null)
          Positioned.fill(
            child: GestureDetector(
              behavior: HitTestBehavior.opaque,
              onTap: widget.onTapOutside,
              child: CustomPaint(
                key: const Key('oi_spotlight_overlay'),
                painter: _SpotlightPainter(
                  targetRect: _targetRect!,
                  overlayColor:
                      widget.overlayColor ?? const Color(0x8A000000),
                  borderRadius: widget.borderRadius,
                ),
              ),
            ),
          ),
      ],
    );
  }
}

/// Paints a dimmed overlay with a transparent cutout around [targetRect].
class _SpotlightPainter extends CustomPainter {
  const _SpotlightPainter({
    required this.targetRect,
    required this.overlayColor,
    this.borderRadius,
  });

  final Rect targetRect;
  final Color overlayColor;
  final BorderRadius? borderRadius;

  @override
  void paint(Canvas canvas, Size size) {
    final fullRect = Offset.zero & size;

    final cutoutPath = Path();
    if (borderRadius != null) {
      cutoutPath.addRRect(borderRadius!.toRRect(targetRect));
    } else {
      cutoutPath.addRect(targetRect);
    }

    final overlayPath = Path.combine(
      PathOperation.difference,
      Path()..addRect(fullRect),
      cutoutPath,
    );

    canvas.drawPath(
      overlayPath,
      Paint()..color = overlayColor,
    );
  }

  @override
  bool shouldRepaint(_SpotlightPainter oldDelegate) =>
      oldDelegate.targetRect != targetRect ||
      oldDelegate.overlayColor != overlayColor ||
      oldDelegate.borderRadius != borderRadius;
}

import 'package:flutter/widgets.dart';
import 'package:obers_ui/src/foundation/theme/oi_theme.dart';

/// An item in the "What's New" dialog.
///
/// Each item represents a single feature or change to display in the
/// [OiWhatsNew] changelog.
///
/// {@category Composites}
class OiWhatsNewItem {
  /// Creates an [OiWhatsNewItem].
  const OiWhatsNewItem({
    required this.title,
    required this.description,
    this.icon,
    this.imageUrl,
    this.version,
  });

  /// The headline for this changelog entry.
  final String title;

  /// A brief description of the feature or change.
  final String description;

  /// An optional icon displayed alongside the item.
  final IconData? icon;

  /// An optional image URL displayed alongside the item.
  ///
  /// Not rendered by default — provided as metadata for custom builders.
  final String? imageUrl;

  /// An optional version badge (e.g. "v2.1.0") shown next to the title.
  final String? version;
}

/// A "What's New" changelog dialog showing recent feature updates.
///
/// Renders a list of [OiWhatsNewItem]s in a dialog-style card with optional
/// version badges and icons. Includes a dismiss button at the bottom.
///
/// {@category Composites}
class OiWhatsNew extends StatelessWidget {
  /// Creates an [OiWhatsNew] dialog.
  const OiWhatsNew({
    required this.items,
    this.onDismiss,
    this.title = "What's New",
    super.key,
  });

  /// The list of changelog items to display.
  final List<OiWhatsNewItem> items;

  /// Called when the user taps the dismiss button.
  final VoidCallback? onDismiss;

  /// The heading displayed at the top of the dialog.
  final String title;

  @override
  Widget build(BuildContext context) {
    final colors = context.colors;
    final textTheme = context.textTheme;

    return Center(
      child: Container(
        key: const Key('oi_whats_new'),
        constraints: const BoxConstraints(maxWidth: 480, minWidth: 280),
        decoration: BoxDecoration(
          color: colors.surface,
          borderRadius: BorderRadius.circular(12),
          boxShadow: [
            BoxShadow(
              color: colors.overlay.withValues(alpha: 0.2),
              blurRadius: 32,
              offset: const Offset(0, 8),
            ),
          ],
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // Header.
            Padding(
              padding: const EdgeInsets.fromLTRB(24, 20, 24, 8),
              child: Text(
                title,
                style: textTheme.h3.copyWith(color: colors.text),
              ),
            ),

            // Items list.
            if (items.isEmpty)
              Padding(
                padding: const EdgeInsets.symmetric(
                  horizontal: 24,
                  vertical: 16,
                ),
                child: Text(
                  'No updates at this time.',
                  key: const Key('oi_whats_new_empty'),
                  style: textTheme.body.copyWith(color: colors.textMuted),
                ),
              )
            else
              Flexible(
                child: ListView.separated(
                  key: const Key('oi_whats_new_list'),
                  shrinkWrap: true,
                  padding: const EdgeInsets.symmetric(
                    horizontal: 24,
                    vertical: 8,
                  ),
                  itemCount: items.length,
                  separatorBuilder: (_, __) => const SizedBox(height: 16),
                  itemBuilder: (context, index) {
                    final item = items[index];
                    return _OiWhatsNewItemTile(item: item);
                  },
                ),
              ),

            // Dismiss button.
            Padding(
              padding: const EdgeInsets.fromLTRB(24, 12, 24, 20),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.end,
                children: [
                  GestureDetector(
                    onTap: onDismiss,
                    child: Container(
                      key: const Key('oi_whats_new_dismiss'),
                      padding: const EdgeInsets.symmetric(
                        horizontal: 16,
                        vertical: 8,
                      ),
                      decoration: BoxDecoration(
                        color: colors.primary.base,
                        borderRadius: BorderRadius.circular(6),
                      ),
                      child: Text(
                        'Got it',
                        style: textTheme.small.copyWith(
                          color: colors.textOnPrimary,
                        ),
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }
}

/// A single item tile within the [OiWhatsNew] list.
class _OiWhatsNewItemTile extends StatelessWidget {
  const _OiWhatsNewItemTile({required this.item});

  final OiWhatsNewItem item;

  @override
  Widget build(BuildContext context) {
    final colors = context.colors;
    final textTheme = context.textTheme;

    return Row(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        // Icon.
        if (item.icon != null)
          Padding(
            padding: const EdgeInsets.only(right: 12, top: 2),
            child: Icon(
              item.icon,
              size: 24,
              color: colors.primary.base,
            ),
          ),

        // Text content.
        Expanded(
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Title row with optional version badge.
              Row(
                children: [
                  Flexible(
                    child: Text(
                      item.title,
                      style: textTheme.bodyStrong.copyWith(
                        color: colors.text,
                      ),
                    ),
                  ),
                  if (item.version != null) ...[
                    const SizedBox(width: 8),
                    Container(
                      key: const Key('oi_whats_new_version'),
                      padding: const EdgeInsets.symmetric(
                        horizontal: 6,
                        vertical: 2,
                      ),
                      decoration: BoxDecoration(
                        color: colors.surfaceActive,
                        borderRadius: BorderRadius.circular(4),
                      ),
                      child: Text(
                        item.version!,
                        style: textTheme.tiny.copyWith(
                          color: colors.textMuted,
                        ),
                      ),
                    ),
                  ],
                ],
              ),
              const SizedBox(height: 4),
              // Description.
              Text(
                item.description,
                style: textTheme.small.copyWith(color: colors.textSubtle),
              ),
            ],
          ),
        ),
      ],
    );
  }
}

import 'dart:math';

import 'package:flutter/physics.dart';

/// Spring physics simulation utilities.
///
/// Provides factory methods for creating [SpringDescription] instances
/// and predefined spring presets for common animation scenarios.
///
/// {@category Utils}
class OiSpringPhysics {
  const OiSpringPhysics._();

  /// Creates a [SpringDescription] from [damping], [stiffness], and [mass].
  ///
  /// These parameters directly map to [SpringDescription]'s constructor.
  static SpringDescription spring({
    double damping = 20.0,
    double stiffness = 180.0,
    double mass = 1.0,
  }) {
    return SpringDescription(
      mass: mass,
      stiffness: stiffness,
      damping: damping,
    );
  }

  /// A slow, gentle spring with minimal bounce.
  ///
  /// Suitable for subtle transitions and background animations.
  static SpringDescription get gentle => const SpringDescription(
        mass: 1,
        stiffness: 100,
        damping: 26,
      );

  /// A balanced spring suitable for most UI animations.
  ///
  /// Provides a natural feel with moderate speed and slight overshoot.
  static SpringDescription get standard => const SpringDescription(
        mass: 1,
        stiffness: 180,
        damping: 20,
      );

  /// A fast, responsive spring with minimal overshoot.
  ///
  /// Suitable for quick interactions like button presses and toggles.
  static SpringDescription get snappy => const SpringDescription(
        mass: 1,
        stiffness: 400,
        damping: 30,
      );

  /// A playful spring with noticeable bounce.
  ///
  /// Suitable for attention-grabbing animations and fun interactions.
  static SpringDescription get bouncy => const SpringDescription(
        mass: 1,
        stiffness: 300,
        damping: 12,
      );

  /// Calculates the approximate duration of a spring animation.
  ///
  /// The duration is estimated as the time it takes for the spring's
  /// amplitude to decay below [threshold] (default 0.001).
  static Duration estimateDuration(
    SpringDescription spring, {
    double threshold = 0.001,
  }) {
    // For a damped harmonic oscillator: amplitude ~ exp(-gamma * t)
    // where gamma = damping / (2 * mass)
    // We solve for t when exp(-gamma * t) = threshold
    // t = -ln(threshold) / gamma

    final gamma = spring.damping / (2.0 * spring.mass);

    if (gamma <= 0) {
      // Undamped: would oscillate forever; return a large duration.
      return const Duration(seconds: 10);
    }

    final seconds = -log(threshold) / gamma;
    final millis = (seconds * 1000).ceil();
    return Duration(milliseconds: millis);
  }
}
